INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('27-patient-os',3,27,'PATIENT OS','He dieu hanh trai nghiem benh nhan',27,'draft','2026-06-20T16:13:11Z','2026-06-20T16:13:11Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e961d022-c563-40ab-aa8c-cef052591428','27-patient-os',NULL,2,'27.1 Định Nghĩa Và Vị Trí Chiến Lược','271-inh-nghia-va-vi-tri-chien-luoc',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a8bb868f-d86a-491a-89dd-84c2f5a4cca7','e961d022-c563-40ab-aa8c-cef052591428',0,'text','T3 CHƯƠNG 27. PATIENT OS - HỆ ĐIỀU HÀNH TRẢI NGHIỆM, CHĂM SÓC VÀ GIỮ CHÂN BỆNH NHÂN TRONG DENTAL EMPIRE OS',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b10255b3-a8fc-4b45-b89a-9b959bb342e6','e961d022-c563-40ab-aa8c-cef052591428',1,'text','**Bộ Não Nuôi Dưỡng Và Khuếch Đại Giá Trị Vòng Đời Bệnh Nhân**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6efa69f8-040d-44ce-84a8-818a7002ec01','27-patient-os','e961d022-c563-40ab-aa8c-cef052591428',3,'Bản chất cốt lõi của Patient OS','ban-chat-cot-loi-cua-patient-os',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('840d3968-b06b-4a35-9775-1a5d882121b2','6efa69f8-040d-44ce-84a8-818a7002ec01',2,'text','Trong kiến trúc tổng thể của Dental Empire OS, nếu Marketing OS có nhiệm vụ tạo nhận biết và xây dựng niềm tin ban đầu, Sales OS chuyển đổi sự quan tâm thành lịch hẹn, và Clinic OS hiện thực hóa cam kết bằng chất lượng điều trị thực tế, thì Patient OS là hệ điều hành quản trị toàn bộ mối quan hệ dài hạn giữa phòng khám và bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86eb02ed-33b5-44d3-a0a8-e3387b980e62','6efa69f8-040d-44ce-84a8-818a7002ec01',3,'text','Nói một cách đơn giản, Patient OS chịu trách nhiệm giúp bệnh nhân không chỉ đến một lần, mà tiếp tục quay lại, gắn bó, tin tưởng và sẵn sàng giới thiệu phòng khám cho người khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('07abefa3-b581-472e-b5b5-731c5a29c9d3','6efa69f8-040d-44ce-84a8-818a7002ec01',4,'text','Nhiều phòng khám hiện nay vẫn xem hoạt động chăm sóc bệnh nhân chỉ là việc gọi điện nhắc lịch hoặc gửi tin nhắn chúc mừng sinh nhật. Tuy nhiên, đó chỉ là những tác vụ đơn lẻ của bộ phận chăm sóc khách hàng, không phải một hệ thống quản trị trải nghiệm bệnh nhân hoàn chỉnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ae1dc63-7acb-43ef-a240-9cc2ccc1ab68','6efa69f8-040d-44ce-84a8-818a7002ec01',5,'text','Patient OS được xây dựng trên một triết lý khác:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('84c33d5b-a10b-40fe-80dc-374f479d5831','6efa69f8-040d-44ce-84a8-818a7002ec01',6,'text','**Bệnh nhân không phải là một giao dịch ngắn hạn mà là một tài sản niềm tin cần được nuôi dưỡng và phát triển trong suốt vòng đời quan hệ với phòng khám.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c66666b8-a1f4-4690-8508-0b73b96c62f7','6efa69f8-040d-44ce-84a8-818a7002ec01',7,'text','Vì vậy, Patient OS không chỉ quản lý các hoạt động sau điều trị mà còn điều phối toàn bộ hành trình trải nghiệm của bệnh nhân. Hệ thống đảm bảo mỗi điểm chạm đều được theo dõi, ghi nhận và tối ưu nhằm duy trì sự hài lòng, gia tăng mức độ gắn kết và xây dựng lòng trung thành theo thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd000819-1e78-481e-b217-f53751a111a8','6efa69f8-040d-44ce-84a8-818a7002ec01',8,'text','Từ thời điểm bệnh nhân lần đầu tương tác với thương hiệu trên môi trường số, đến quá trình thăm khám, điều trị, tái khám, chăm sóc định kỳ và nhiều năm sau đó, Patient OS đóng vai trò như một cơ chế vận hành liên tục giúp phòng khám duy trì kết nối, tạo giá trị và phát triển mối quan hệ bền vững với từng bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c9de5a4e-844e-4965-bf65-6b821520c1a3','6efa69f8-040d-44ce-84a8-818a7002ec01',9,'text','Ở góc độ quản trị, Patient OS là hệ thống biến một bệnh nhân đã điều trị thành ba tài sản tăng trưởng quan trọng cho phòng khám:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c17b13bd-f74f-4c7e-b49b-720d680cb53b','6efa69f8-040d-44ce-84a8-818a7002ec01',10,'text','- **Bệnh nhân quay lại điều trị và tái khám định kỳ.**- **Bệnh nhân để lại đánh giá tích cực và tạo dựng uy tín thương hiệu.**- **Bệnh nhân giới thiệu người thân, bạn bè và đồng nghiệp đến phòng khám.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6591ef07-b898-4453-a442-a1a8cd1fd575','6efa69f8-040d-44ce-84a8-818a7002ec01',11,'text','Đó chính là nền tảng giúp nha khoa chuyển dịch từ mô hình tăng trưởng phụ thuộc vào khách hàng mới sang mô hình tăng trưởng bền vững dựa trên giá trị vòng đời bệnh nhân và sức mạnh của niềm tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('513fc411-9751-42d6-8614-fd471073883e','27-patient-os','e961d022-c563-40ab-aa8c-cef052591428',3,'Sự khác biệt bản chất giữa CSKH truyền thống và Patient OS','su-khac-biet-ban-chat-giua-cskh-truyen-thong-va-patient-os',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('67abec25-c1b9-4464-9706-0f1d410a867a','513fc411-9751-42d6-8614-fd471073883e',12,'text','Để hiểu rõ tư duy công nghiệp hóa trải nghiệm, bảng đối soát dưới đây bóc tách rõ ranh giới giữa cách làm bản năng cũ và hệ điều hành số hóa mới:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9acecd00-3bf9-486b-8588-98592f4c0160','513fc411-9751-42d6-8614-fd471073883e',13,'image',NULL,'book/27-patient-os/8eb33952-de09-4099-a75f-4963b181d0cb-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e6c645be-8938-4658-bae1-56001f4b419b','27-patient-os','e961d022-c563-40ab-aa8c-cef052591428',3,'Sáu giá trị đầu ra cốt lõi của Patient OS','sau-gia-tri-au-ra-cot-loi-cua-patient-os',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b7b756f0-2b07-4977-aba1-ea82eb371e2d','e6c645be-8938-4658-bae1-56001f4b419b',14,'text','Khi Patient OS được triển khai bài bản và vận hành đồng bộ với toàn bộ hệ thống phòng khám, đây không chỉ là một công cụ chăm sóc sau điều trị mà còn trở thành động cơ tăng trưởng dài hạn, liên tục tạo ra những giá trị bền vững cho nha khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e17ab47f-c8c4-4458-bfad-b7224db6bd1c','27-patient-os','e6c645be-8938-4658-bae1-56001f4b419b',4,'3.1. Nâng cao trải nghiệm bệnh nhân toàn diện (Patient Experience)','31-nang-cao-trai-nghiem-benh-nhan-toan-dien-patient-experience',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8ee2373-adb2-4ff2-9d61-907177c0487e','e17ab47f-c8c4-4458-bfad-b7224db6bd1c',15,'text','Giúp bệnh nhân luôn cảm thấy được quan tâm, lắng nghe và đồng hành xuyên suốt hành trình điều trị. Từ những hướng dẫn sau điều trị đến các tương tác chăm sóc định kỳ, Patient OS góp phần giảm cảm giác lo lắng, bối rối và tăng sự an tâm ngay cả khi bệnh nhân đã rời phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('73f56a08-fb7c-437e-83c4-ddc86af2dfac','27-patient-os','e6c645be-8938-4658-bae1-56001f4b419b',4,'3.2. Gia tăng tỷ lệ tái khám và chăm sóc định kỳ (Recall Rate)','32-gia-tang-ty-le-tai-kham-va-cham-soc-inh-ky-recall-rate',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e2c431b-4557-4195-a1db-3b0909c46834','73f56a08-fb7c-437e-83c4-ddc86af2dfac',16,'text','Tự động hóa các hoạt động nhắc lịch kiểm tra, cạo vôi, tái khám và theo dõi kết quả điều trị đúng thời điểm. Qua đó hình thành thói quen chăm sóc sức khỏe răng miệng chủ động và duy trì mối liên hệ thường xuyên giữa bệnh nhân với phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0dc12a8b-2a54-453b-949c-9ebe53a1cfef','27-patient-os','e6c645be-8938-4658-bae1-56001f4b419b',4,'3.3. Tạo nguồn Review chất lượng bền vững','33-tao-nguon-review-chat-luong-ben-vung',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f5a5423-af03-47e8-b89c-59e3b5963e9c','0dc12a8b-2a54-453b-949c-9ebe53a1cfef',17,'text','Xác định đúng thời điểm và đúng đối tượng để mời đánh giá trải nghiệm. Hệ thống giúp gia tăng số lượng review tích cực trên các nền tảng như Google Maps, góp phần củng cố uy tín thương hiệu và nâng cao hiệu quả hiện diện tìm kiếm địa phương.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ae1dbeb3-7cee-425f-8942-f2d9cd1441eb','27-patient-os','e6c645be-8938-4658-bae1-56001f4b419b',4,'3.4. Thúc đẩy giới thiệu tự nhiên (Referral Growth)','34-thuc-ay-gioi-thieu-tu-nhien-referral-growth',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('22e665f0-2c3a-48ff-9bb3-1111b99ff2a4','ae1dbeb3-7cee-425f-8942-f2d9cd1441eb',18,'text','Biến những bệnh nhân hài lòng thành những người sẵn sàng chia sẻ trải nghiệm tích cực với người thân, bạn bè và đồng nghiệp. Đây là nguồn khách hàng chất lượng cao với mức độ tin tưởng lớn và chi phí thu hút gần như bằng không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('80886c01-5fa5-436b-8133-bfefc0094379','27-patient-os','e6c645be-8938-4658-bae1-56001f4b419b',4,'3.5. Tích lũy tài sản niềm tin cho thương hiệu (Trust Assets)','35-tich-luy-tai-san-niem-tin-cho-thuong-hieu-trust-assets',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5bad309d-1e60-4da7-880a-b3ab6404a608','80886c01-5fa5-436b-8133-bfefc0094379',19,'text','Thu thập và chuẩn hóa các phản hồi, câu chuyện điều trị thành công, hình ảnh và cảm nhận thực tế từ bệnh nhân. Những dữ liệu này trở thành nguồn nguyên liệu giá trị cho Website, Google Maps, TikTok, Facebook và các hoạt động truyền thông của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cf641c82-55d4-4490-b9cf-6cbdcb7d7481','27-patient-os','e6c645be-8938-4658-bae1-56001f4b419b',4,'3.6. Tối ưu hóa giá trị vòng đời bệnh nhân (Patient Lifetime Value - LTV)','36-toi-uu-hoa-gia-tri-vong-oi-benh-nhan-patient-lifetime-value-ltv',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0bb957e1-324d-408e-a698-ec89886eb68a','cf641c82-55d4-4490-b9cf-6cbdcb7d7481',20,'text','Thay vì chỉ tập trung vào doanh thu từ một lần điều trị, Patient OS giúp xây dựng mối quan hệ dài hạn với bệnh nhân thông qua tái khám, điều trị bổ sung, chăm sóc định kỳ và giới thiệu người thân. Nhờ đó, giá trị tạo ra trên mỗi hồ sơ bệnh nhân được gia tăng theo thời gian một cách bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('75d30f46-d5f1-4d1b-9f59-f06ecdba8203','cf641c82-55d4-4490-b9cf-6cbdcb7d7481',21,'text','*Tóm lại, Patient OS không chỉ giúp chăm sóc bệnh nhân tốt hơn mà còn biến mỗi bệnh nhân hiện hữu thành một tài sản tăng trưởng dài hạn của phòng khám thông qua ba kết quả cốt lõi: Tái khám nhiều hơn – Đánh giá tốt hơn – Giới thiệu nhiều hơn.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('34e6fccf-5a71-44cf-94ed-08f7855db050','27-patient-os','e961d022-c563-40ab-aa8c-cef052591428',3,'Phương Trình Khuếch Đại Giá Trị Vòng Đời Bệnh Nhân (Patient Lifetime Value - LTV)','phuong-trinh-khuech-ai-gia-tri-vong-oi-benh-nhan-patient-lifetime-value-ltv',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('67214d87-074c-4000-adb1-aca93891853e','34e6fccf-5a71-44cf-94ed-08f7855db050',22,'text','Patient OS được thiết kế để tối ưu hóa giá trị dài hạn của mỗi bệnh nhân, thay vì chỉ tập trung vào doanh thu của một lần điều trị. Hiệu quả vận hành của hệ thống được đo lường thông qua chỉ số **Giá trị Vòng đời Bệnh nhân (Patient Lifetime Value - LTV)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3edede1-aa07-4de2-bc19-a73ceab67051','34e6fccf-5a71-44cf-94ed-08f7855db050',23,'image',NULL,'book/27-patient-os/828c0fb8-0cf2-484b-aeee-13a06e033028-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da128f59-2c2a-41d2-a23b-c3af878a89dc','34e6fccf-5a71-44cf-94ed-08f7855db050',24,'text','**Mantra điều hành Patient OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7b4afe4-f643-44dc-88df-b8a630ef64b1','34e6fccf-5a71-44cf-94ed-08f7855db050',25,'text','*"Một phòng khám nha khoa tầm thường chỉ sống bằng những ca điều trị đứt đoạn ở hiện tại. Một đế chế nha khoa bền vững tăng trưởng dựa trên pháo đài lòng tin tích lũy của bệnh nhân ở tương lai. Hãy điều hành khâu chăm sóc bằng sự tử tế được số hóa cấu phần để không một khách hàng nào bị lãng quên."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('84c758e8-c555-4010-9dc5-d2acda343cc5','27-patient-os',NULL,2,'27.2 Vai trò của Patient OS','272-vai-tro-cua-patient-os',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fdde94c5-c3b9-4db6-bd75-280443413cb8','84c758e8-c555-4010-9dc5-d2acda343cc5',26,'text','Nếu coi toàn bộ hệ thống vận hành nha khoa là một chuỗi chuyển hóa năng lượng, thì **Patient OS** chính là điểm bản lề chuyển cấu trúc từ tuyến tính (chạy một chiều từ đầu phễu đến cuối phễu) sang mô hình vòng lặp vô tận (Flywheel). Phân hệ này nằm ở chặng sau chuyển đổi và sau điều trị, nhận Payload dữ liệu lâm sàng sạch từ *Clinic OS* để kích hoạt các phản ứng tăng trưởng chuỗi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('54da2f28-769b-4995-91a5-8816bf379081','27-patient-os','84c758e8-c555-4010-9dc5-d2acda343cc5',3,'Đường Ống Dịch Chuyển Dữ Liệu Toàn Hệ Thống','uong-ong-dich-chuyen-du-lieu-toan-he-thong',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('47d843bf-255d-4f45-bd94-437ed7c7dd10','54da2f28-769b-4995-91a5-8816bf379081',27,'text','Trong **Dental Empire OS**, hành trình của một hồ sơ khách hàng không bao giờ có điểm kết thúc. Hồ sơ đó dịch chuyển tuần tự qua các phân hệ core theo trục dọc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('806c4c1f-3c47-484a-a3bb-969a54c0d00a','54da2f28-769b-4995-91a5-8816bf379081',28,'image',NULL,'book/27-patient-os/8f6dfa02-511c-4182-bf1f-793db370b50a-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5c2a512d-9b5f-4c2e-9b1b-27506fc316da','27-patient-os','84c758e8-c555-4010-9dc5-d2acda343cc5',3,'Bẻ Gãy "Chứng Nghiện Paid Ads" Bằng Hệ Thống Giữ Chân','be-gay-chung-nghien-paid-ads-bang-he-thong-giu-chan',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b6b51928-559c-4aa0-8b26-feff1d155183','5c2a512d-9b5f-4c2e-9b1b-27506fc316da',29,'text','Một phòng khám nha khoa chỉ tập trung vào nửa đầu phễu (Marketing và Sales) giống như việc cố gắng đổ nước vào một chiếc xô thủng đáy. Chi phí thu hút một khách hàng mới (CAC) tại thị trường ngày càng leo thang và ăn mòn biên lợi nhuận ròng của các ca lớn. Nếu để bệnh nhân rời đi ngay sau khi tháo khay niềng hay cấy xong Implant, phòng khám sẽ mãi mãi bị mắc kẹt trong cái bẫy:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e83025c9-5359-4f86-aeda-97301e6dbe58','5c2a512d-9b5f-4c2e-9b1b-27506fc316da',30,'text','**Ngừng đổ tiền quảng cáo = Ngừng dòng khách.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00ddaa86-a0ca-4c51-ab7d-7fb84a0d1d4a','5c2a512d-9b5f-4c2e-9b1b-27506fc316da',31,'text','Ngược lại, khi **Patient OS** được setup chuẩn xác, nó sẽ giải phóng phòng khám khỏi sự phụ thuộc vào thuật toán phân phối của các nền tảng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b7fa32aa-f2e9-4239-a56a-89187c29a0e8','5c2a512d-9b5f-4c2e-9b1b-27506fc316da',32,'text','- **Tái định nghĩa "Khách hàng":** Bệnh nhân không còn là người chi trả một hóa đơn đơn lẻ. Họ trở thành một "Tài sản tăng trưởng" liên tục sản sinh ra giá trị thông qua tiếng vang thương hiệu (Word-of-Mouth) và dữ liệu thực chứng sạch (User-Generated Content).- **Tối ưu chỉ số hiệu suất:** Giảm áp lực lên Marketing OS bằng cách tự động bù đắp dòng khách thiếu hụt bằng nguồn khách giới thiệu hữu cơ có chi phí CAC bằng 0.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6532117-be5e-435a-b557-40d168f7dbea','5c2a512d-9b5f-4c2e-9b1b-27506fc316da',33,'text','**Mantra cốt lõi của Trạm cầu nối:***"Marketing OS và Sales OS đưa bệnh nhân đến cửa. Clinic OS giải quyết nỗi đau lâm sàng trên ghế nha. Nhưng chính Patient OS mới là phân hệ quyết định bệnh nhân đó sẽ ra đi trong im lặng hay trở thành một chiến binh truyền thông, kiên trì mang thêm 10 khách hàng mới về cho phòng khám."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3d46795e-af5d-477e-8825-17f5ba9f9b96','27-patient-os',NULL,2,'27.3 Sáu Trụ Mục Tiêu Chiến Lược Của Patient OS','273-sau-tru-muc-tieu-chien-luoc-cua-patient-os',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('de9fb937-7b16-4462-a71e-9d6432d2449c','3d46795e-af5d-477e-8825-17f5ba9f9b96',34,'text','Để hệ thống nha khoa **Thích Làm Răng** vận hành ổn định và không lãng phí tài nguyên khách hàng, phân hệ **Patient OS** tập trung giải quyết trọn vẹn 6 mục tiêu chiến lược cốt lõi dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('20ad3082-a0e8-4ddb-8250-1e054a0441a2','27-patient-os','3d46795e-af5d-477e-8825-17f5ba9f9b96',3,'Đảm bảo bệnh nhân được chăm sóc xuyên suốt (Continuous Care)','am-bao-benh-nhan-uoc-cham-soc-xuyen-suot-continuous-care',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a094342-9884-4a90-9ba1-8c75e9738cf1','20ad3082-a0e8-4ddb-8250-1e054a0441a2',35,'text','- **Bản chất:** Gỡ bỏ hoàn toàn trạng thái "bị bỏ rơi" của người bệnh sau khi họ đã hoàn tất thanh toán chi phí hoặc kết thúc thủ thuật tại ghế nha.- **Hành động chuẩn hóa:** Thiết lập luồng liên lạc cố định từ phòng khám đến khách hàng trong suốt giai đoạn hậu phẫu tại nhà. Nhân sự trực ca phải chủ động hỏi thăm, đồng hành để giải tỏa tâm lý lo lắng và hướng dẫn khách xử lý các phản ứng sinh học bình thường (như sưng nhẹ hoặc ê ẩm) theo đúng chỉ dẫn của Bác sĩ Vinh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4066b098-bf0d-403b-b851-1534787ac768','27-patient-os','3d46795e-af5d-477e-8825-17f5ba9f9b96',3,'Tối ưu hóa tỷ lệ quay lại (Patient Retention)','toi-uu-hoa-ty-le-quay-lai-patient-retention',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('896297e1-1f9d-4323-80e1-24d254ca4774','4066b098-bf0d-403b-b851-1534787ac768',36,'text','- **Bản chất:** Nuôi dưỡng tệp khách hàng cũ để họ tự giác quay lại phòng khám theo chu kỳ, thay vì để họ im lặng rời đi sau một lần điều trị.- **Hành động chuẩn hóa:** Hệ thống CRM tự động lập lịch theo dõi tiến trình lành thương hoặc dịch chuyển răng. Nhân sự chủ động nhắc lịch Recall sinh học (cạo vôi răng, kiểm tra khớp cắn) và gợi ý các lộ trình điều trị phụ trợ phù hợp tiếp theo (như tẩy trắng răng sau khi tháo niềng) đúng thời điểm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1be3481e-27cd-469e-b794-9878fdf25322','27-patient-os','3d46795e-af5d-477e-8825-17f5ba9f9b96',3,'Nâng cao chỉ số hài lòng toàn diện (Patient Satisfaction)','nang-cao-chi-so-hai-long-toan-dien-patient-satisfaction',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('59eecdf7-4725-475c-903d-1f062f92b988','1be3481e-27cd-469e-b794-9878fdf25322',37,'text','- **Bản chất:** Đồng bộ hóa chất lượng dịch vụ ở mọi điểm chạm vật lý lẫn kỹ thuật số, giúp khách hàng có trải nghiệm đồng nhất.- **Hành động chuẩn hóa:** Quy định rõ SLA hành vi cho từng vị trí. Sự hài lòng của bệnh nhân phải được xây dựng từ quy trình tiếp đón nhanh chóng của lễ tân, sự minh bạch trong khâu tư vấn tài chính của TCO, lời giải thích chuyên môn dễ hiểu của bác sĩ và dịch vụ hậu mãi chu đáo của đội ngũ CSKH.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a64ff089-42e5-4f02-9704-759a4a260459','27-patient-os','3d46795e-af5d-477e-8825-17f5ba9f9b96',3,'Thu hoạch Review và Testimonial (Trust Asset Acquisition)','thu-hoach-review-va-testimonial-trust-asset-acquisition',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('14de004b-5c57-4572-a438-36aeff1d3289','a64ff089-42e5-4f02-9704-759a4a260459',38,'text','- **Bản chất:** Kích hoạt tính chủ động của người bệnh để biến sự hài lòng của họ thành tài sản uy tín, phục vụ ngược lại cho khâu Marketing đầu phễu.- **Hành động chuẩn hóa:** Nhân sự CSKH nhận diện thời điểm bệnh nhân đạt đỉnh cao hạnh phúc (`Peak Wow` - ví dụ: ngày tháo niềng răng hoặc ngày lắp răng sứ trên trụ Implant). Tại thời điểm này, kích hoạt kịch bản hướng dẫn khách để lại đánh giá 5 sao trên Google Maps hoặc quay video ngắn chia sẻ câu chuyện điều trị thực tế để đăng tải lên kênh TikTok.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('800680f8-75a4-4194-b6a7-c3a737210519','27-patient-os','3d46795e-af5d-477e-8825-17f5ba9f9b96',3,'Tạo nguồn khách giới thiệu tự nhiên (Referral Growth)','tao-nguon-khach-gioi-thieu-tu-nhien-referral-growth',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('629990ac-e328-4d57-b0be-7f93ab3ecfef','800680f8-75a4-4194-b6a7-c3a737210519',39,'text','- **Bản chất:** Biến một bệnh nhân cũ thành một kênh phân phối hữu cơ, giúp giảm chi phí thu hút khách hàng mới (CAC).- **Hành động chuẩn hóa:** Khi bệnh nhân cũ được bao bọc bằng một dịch vụ tử tế và có kết quả lâm sàng tốt, họ sẽ tự tin giới thiệu cho người thân, bạn bè và đồng nghiệp. Hệ thống Patient OS cung cấp các chương trình đặc quyền hội viên (Voucher chăm sóc răng miễn phí cho gia đình) để thúc đẩy luồng giới thiệu này diễn ra tự nhiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('af92d2d0-50a4-454f-bafe-b699b26e740d','27-patient-os','3d46795e-af5d-477e-8825-17f5ba9f9b96',3,'Xây dựng cộng đồng bệnh nhân trung thành (Community Building)','xay-dung-cong-ong-benh-nhan-trung-thanh-community-building',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f0ad5d9-7d74-4c10-8e0d-f61f0fcc5514','af92d2d0-50a4-454f-bafe-b699b26e740d',40,'text','- **Bản chất:** Thay đổi bản chất mối quan hệ từ "Giao dịch thương mại một lần" sang "Gắn bó dài hạn trọn đời".- **Hành động chuẩn hóa:** Phòng khám duy trì việc cung cấp giá trị tri thức sạch cho khách hàng thông qua các bản tin Zalo OA cá nhân hóa. Bệnh nhân xem nha khoa Thích Làm Răng là nơi bảo trợ sức khỏe răng miệng cho cả gia đình, sẵn sàng quay lại kiểm tra định kỳ mỗi năm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bbe40746-9e3b-4e6e-85c5-1de51196da0c','27-patient-os','3d46795e-af5d-477e-8825-17f5ba9f9b96',3,'Bảng Đối Soát Mục Tiêu Và Chỉ Số Kiểm Soát (KPI Matrix)','bang-oi-soat-muc-tieu-va-chi-so-kiem-soat-kpi-matrix',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0e866090-fe62-48ff-ae3e-7656ad9a2367','bbe40746-9e3b-4e6e-85c5-1de51196da0c',41,'text','Để Ban quản lý phòng khám dễ dàng theo dõi hiệu suất, 6 mục tiêu trên được quy đổi thành các chỉ số định lượng cụ thể:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e7598dae-9ad6-46dd-8082-0bb4f9279b07','bbe40746-9e3b-4e6e-85c5-1de51196da0c',42,'image',NULL,'book/27-patient-os/6d468b55-ad6c-4312-bff1-0b1e0d591190-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cab213f9-f526-401e-841d-1b14c766d9e6','bbe40746-9e3b-4e6e-85c5-1de51196da0c',43,'text','**Mantra điều hành mục tiêu:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('020e2d95-0b62-4768-a695-cafe8bfee669','bbe40746-9e3b-4e6e-85c5-1de51196da0c',44,'text','*"Mục tiêu của Patient OS không phải là cố gắng tìm cách bán thêm dịch vụ để thu tiền của người bệnh. Mục tiêu tối hậu là làm tốt khâu chăm sóc và minh bạch thông tin, khiến bệnh nhân hoàn toàn an tâm và tự nguyện ở lại trong hệ thống của chúng ta."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4a38bbb1-f681-458a-9e89-d139516865f3','27-patient-os',NULL,2,'27.4 Tư Duy Cốt Lõi Của Patient OS: Điều Trị Xong Mới Là Bắt Đầu','274-tu-duy-cot-loi-cua-patient-os-ieu-tri-xong-moi-la-bat-au',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ea716a63-4ef4-4e48-a655-5e33a37ea31e','4a38bbb1-f681-458a-9e89-d139516865f3',45,'text','Sự khác biệt lớn nhất giữa một nha khoa vận hành ngắn hạn và một phòng khám phát triển bền vững nằm ở cách nhìn nhận về thời điểm bệnh nhân hoàn tất ca điều trị. Khi người bệnh bước xuống khỏi ghế nha và thanh toán xong hóa đơn, đó không phải là lúc phòng khám dừng việc chăm sóc, mà là thời điểm kích hoạt một mối quan hệ dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8f7c5b4c-d028-4280-994b-c48241460614','27-patient-os','4a38bbb1-f681-458a-9e89-d139516865f3',3,'Ma trận dịch chuyển tư duy vận hành phòng khám','ma-tran-dich-chuyen-tu-duy-van-hanh-phong-kham',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8f03d501-d2bd-4d6b-84d0-43f4a3d3bbcc','8f7c5b4c-d028-4280-994b-c48241460614',46,'text','Để bộ máy nhân sự tại Hà Nội đồng bộ cách làm việc, phòng khám cần xóa bỏ tư duy bản năng cũ và quán triệt tư duy hệ thống mới:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c7ac6ed-4ba3-4ef0-93f6-2a7c59516f22','8f7c5b4c-d028-4280-994b-c48241460614',47,'text','Dưới đây là phiên bản được viết lại theo phong cách chuyên nghiệp, hiện đại và mang tính quản trị hệ thống hơn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2187b7db-b926-423f-9a6c-cd53d22265c2','27-patient-os','4a38bbb1-f681-458a-9e89-d139516865f3',3,'Vai Trò Chuyển Hóa Của Bệnh Nhân Sau Điều Trị','vai-tro-chuyen-hoa-cua-benh-nhan-sau-ieu-tri',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('542cbba3-6f27-46c7-9372-cb1a6880a579','2187b7db-b926-423f-9a6c-cd53d22265c2',48,'text','Một trong những nhiệm vụ quan trọng nhất của Patient OS là chuyển hóa kết quả điều trị thành giá trị tăng trưởng dài hạn cho phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('487edba7-812f-44b2-9269-757cc523179b','2187b7db-b926-423f-9a6c-cd53d22265c2',49,'text','Khi bệnh nhân được chăm sóc đúng quy trình, duy trì kết nối sau điều trị và liên tục nhận được giá trị từ hệ thống, họ sẽ không còn là một khách hàng hoàn tất giao dịch rồi rời đi. Thay vào đó, họ dần trở thành những tài sản tăng trưởng có khả năng tạo ra doanh thu, uy tín và cơ hội phát triển mới cho phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4abbf01-e8ad-4b52-9634-a6b4475ced54','2187b7db-b926-423f-9a6c-cd53d22265c2',50,'text','Patient OS được thiết kế để thúc đẩy quá trình chuyển hóa này thông qua bảy nhóm tài sản chiến lược.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9c33d6a5-3dfd-42a5-9502-6aede1eb19f2','27-patient-os','2187b7db-b926-423f-9a6c-cd53d22265c2',4,'2.1 Bệnh Nhân Tái Khám Định Kỳ','21-benh-nhan-tai-kham-inh-ky',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9affd084-c3eb-4a77-a4e1-5c391ad3f290','9c33d6a5-3dfd-42a5-9502-6aede1eb19f2',51,'text','Bệnh nhân chủ động quay lại để kiểm tra, vệ sinh răng miệng, theo dõi kết quả điều trị và thực hiện các chương trình chăm sóc định kỳ theo lịch hẹn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2ea9252d-456f-4895-9f53-c58b64183436','9c33d6a5-3dfd-42a5-9502-6aede1eb19f2',52,'text','Đây là nguồn doanh thu ổn định và là nền tảng giúp phòng khám duy trì công suất vận hành bền vững theo thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1a58ca9f-fc1f-4e2d-bd06-79058637f941','27-patient-os','2187b7db-b926-423f-9a6c-cd53d22265c2',4,'2.2. Bệnh Nhân Tiếp Tục Sử Dụng Dịch Vụ','22-benh-nhan-tiep-tuc-su-dung-dich-vu',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7dcdde4f-407f-45b4-a78a-fcce0e378515','1a58ca9f-fc1f-4e2d-bd06-79058637f941',53,'text','Sau khi trải nghiệm thành công một dịch vụ, bệnh nhân có xu hướng tin tưởng và lựa chọn phòng khám cho những nhu cầu điều trị khác trong tương lai.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0d7fe6d-b70a-47af-b5fe-caf43bb117ab','1a58ca9f-fc1f-4e2d-bd06-79058637f941',54,'text','Điều này giúp gia tăng giá trị vòng đời bệnh nhân (LTV) và giảm sự phụ thuộc vào nguồn khách hàng mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c071d695-c117-44a4-bde7-30bbf0b982ac','27-patient-os','2187b7db-b926-423f-9a6c-cd53d22265c2',4,'2.3. Người Tạo Ra Review Và Social Proof','23-nguoi-tao-ra-review-va-social-proof',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4e4df5c-38ce-40ff-aab6-b4815c7d7591','c071d695-c117-44a4-bde7-30bbf0b982ac',55,'text','Những bệnh nhân hài lòng sẵn sàng chia sẻ trải nghiệm thực tế thông qua đánh giá trên Google Maps, Fanpage hoặc các nền tảng trực tuyến khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7443febb-09dc-4e17-b317-a9c05d1b4795','c071d695-c117-44a4-bde7-30bbf0b982ac',56,'text','Các đánh giá này góp phần nâng cao uy tín thương hiệu, cải thiện hiệu quả tìm kiếm địa phương và tăng tỷ lệ chuyển đổi của khách hàng mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a9440793-e340-4bce-a384-33e914612fd1','27-patient-os','2187b7db-b926-423f-9a6c-cd53d22265c2',4,'2.4. Người Giới Thiệu Khách Hàng Mới','24-nguoi-gioi-thieu-khach-hang-moi',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c138d71-e0da-4606-9f7c-8f8dd7dac42d','a9440793-e340-4bce-a384-33e914612fd1',57,'text','Niềm tin của bệnh nhân là hình thức marketing có sức thuyết phục mạnh nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f31378e8-9b0f-400b-946c-ef87f28bf805','a9440793-e340-4bce-a384-33e914612fd1',58,'text','Khi một bệnh nhân chủ động giới thiệu người thân, bạn bè hoặc đồng nghiệp đến phòng khám, phòng khám sẽ có thêm nguồn khách hàng chất lượng cao với chi phí thu hút gần như bằng không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cb15acf4-c47b-4c4c-b70d-5523f4483ecd','27-patient-os','2187b7db-b926-423f-9a6c-cd53d22265c2',4,'2.5. Nhân Vật Trong Case Study Và Nội Dung Thực Chứng','25-nhan-vat-trong-case-study-va-noi-dung-thuc-chung',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b028cf3-07ae-4ce2-94ce-b04c39fce0bb','cb15acf4-c47b-4c4c-b70d-5523f4483ecd',59,'text','Những bệnh nhân đồng ý chia sẻ hành trình điều trị sẽ trở thành nguồn dữ liệu thực tế quý giá cho hoạt động truyền thông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37722bee-c12c-43cb-98e6-a8db9cba8821','cb15acf4-c47b-4c4c-b70d-5523f4483ecd',60,'text','Hình ảnh Before–After, video cảm nhận, câu chuyện điều trị và các minh chứng lâm sàng giúp phòng khám xây dựng kho tài sản niềm tin ngày càng phong phú và thuyết phục hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c631c1a7-04e1-4d89-8f48-2f74b1a01650','27-patient-os','2187b7db-b926-423f-9a6c-cd53d22265c2',4,'2.6. Thành Viên Cộng Đồng Khách Hàng Trung Thành','26-thanh-vien-cong-ong-khach-hang-trung-thanh',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9a8d076f-387e-4196-8e6a-e3f2f3915389','c631c1a7-04e1-4d89-8f48-2f74b1a01650',61,'text','Bệnh nhân không chỉ quay lại sử dụng dịch vụ mà còn duy trì tương tác với thương hiệu thông qua các chương trình chăm sóc, hoạt động cộng đồng và nội dung giáo dục sức khỏe răng miệng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('77cd2383-fd3d-4a79-a866-f4a140d6db6e','c631c1a7-04e1-4d89-8f48-2f74b1a01650',62,'text','Đây là nền tảng để hình thành một cộng đồng khách hàng gắn bó lâu dài với phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('01723e0f-3652-42c8-8bd0-b8042e003f2c','27-patient-os','2187b7db-b926-423f-9a6c-cd53d22265c2',4,'2.7. Người Bảo Chứng Cho Uy Tín Thương Hiệu','27-nguoi-bao-chung-cho-uy-tin-thuong-hieu',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0f969ca8-a030-4d17-aefb-8782d951a263','01723e0f-3652-42c8-8bd0-b8042e003f2c',63,'text','Sau nhiều năm trải nghiệm tích cực, bệnh nhân trở thành những người xác nhận đáng tin cậy nhất cho chất lượng dịch vụ của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2304bc2b-144d-446a-a3ba-2c35264b181e','01723e0f-3652-42c8-8bd0-b8042e003f2c',64,'text','Tiếng nói khách quan từ những bệnh nhân thực tế thường có sức thuyết phục lớn hơn bất kỳ thông điệp quảng cáo nào và góp phần bảo vệ uy tín thương hiệu trong môi trường cạnh tranh ngày càng cao.',NULL,NULL,NULL,NULL,NULL);
