INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('12822c85-7f94-4c6f-b223-68d7c533c0d5','8322a290-2802-4b05-82a9-3f5eb4976f41',68,'text','Chặng Pre-Visit Care kiểm soát khoảng thời gian từ lúc bệnh nhân chốt lịch hẹn trực tuyến đến trước khi họ đặt chân vào sảnh nha khoa **Thích Làm Răng**. Mục tiêu của giai đoạn này tập trung vào các đầu việc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('856cc850-521a-427f-984d-ea5bc8eb39f9','8322a290-2802-4b05-82a9-3f5eb4976f41',69,'text','- **Giảm tỷ lệ hủy lịch và bùng hẹn (No-show):** Khóa cứng cam kết có mặt của khách hàng thông qua chuỗi nhắc nhớ chủ động.- **Tăng cảm giác chuyên nghiệp:** Thể hiện sự chuẩn bị chu đáo của phòng khám, tạo mỏ neo tin tưởng ngay từ xa.- **Chuẩn bị tâm lý và hồ sơ lâm sàng:** Hướng dẫn bệnh nhân chuẩn bị sẵn các giấy tờ cần thiết hoặc lưu ý sức khỏe trước khi lên ghế điều trị.',NULL,NULL,NULL,NULL,NULL);
