INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2c6675a-b8aa-4a8e-b933-e87a00db9894','06ce8d7e-d819-4582-82c8-463810a3c578',76,'text','- **Địa chỉ phòng khám:** [Địa chỉ cơ sở Hà Nội]- **Bản đồ Google Maps:** [Link_Bản_Đồ]- **Hướng dẫn gửi xe:** Phòng khám có khu vực đỗ xe máy và xe ô tô miễn phí ngay phía trước cửa, nhân viên bảo vệ sẽ hỗ trợ anh/chị khi đến nơi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78ae3fae-f4a3-4286-a237-4e967563c6c3','06ce8d7e-d819-4582-82c8-463810a3c578',77,'text','Anh/chị vui lòng có mặt trước giờ hẹn khoảng 5–10 phút để bộ phận Lễ tân hỗ trợ hoàn tất các thủ tục tiếp nhận hồ sơ ban đầu nhé ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bcc2a393-8cb6-4304-8350-309aead17a63','06ce8d7e-d819-4582-82c8-463810a3c578',78,'text','Nếu cần thay đổi hoặc điều chỉnh lại khung giờ hẹn, anh/chị vui lòng nhắn lại sớm tại đây để em hỗ trợ sắp xếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ac2340c4-da9a-48e5-be00-1bad46da3834','06ce8d7e-d819-4582-82c8-463810a3c578',79,'text','Mẫu 2: Nhắc nhớ và lưu ý chuẩn bị lâm sàng (Gửi trước 12 tiếng)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6cb452b4-0afb-404b-9174-e441d189fa1c','06ce8d7e-d819-4582-82c8-463810a3c578',80,'text','**Chào anh/chị [Tên_Khách_Hàng],**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('43e24e7a-73ad-4f49-b5ec-db2500c626c8','06ce8d7e-d819-4582-82c8-463810a3c578',81,'text','Để buổi hẹn điều trị răng vào lúc **[Giờ_Hẹn] ngày mai** diễn ra thuận lợi và an toàn nhất, nha khoa có một vài lưu ý nhỏ gửi đến anh/chị:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ae677ce0-b735-4a9f-b059-01f8c33a5e94','06ce8d7e-d819-4582-82c8-463810a3c578',82,'text','- Anh/chị nhớ ăn uống đầy đủ trước khi qua phòng khám (đặc biệt đối với lịch hẹn tiểu phẫu nhổ răng khôn hoặc cấy trụ Implant).- Vui lòng mang theo các phim chụp X-quang răng cũ hoặc đơn thuốc bệnh lý nền đang sử dụng gần đây (nếu có) để Bác sĩ tiện đối soát chuyên môn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ac9777c3-6bfc-4003-b80a-4680bab2c2f4','06ce8d7e-d819-4582-82c8-463810a3c578',83,'text','Phòng VIP và ekip của Bác sĩ Nguyễn Phước Vinh đã sẵn sàng để tiếp đón anh/chị ngày mai. Chúc anh/chị một buổi tối thư thả!',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('941c88f8-0267-44e9-b0dd-473930e7d327','27-patient-os','1d1814f6-c55f-4f20-9023-bc8df3d04b5d',4,'Chỉ Số Quản Trị Cốt Lõi (Guardrail Metric)','chi-so-quan-tri-cot-loi-guardrail-metric',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85dcd575-06e3-4714-a447-71b2767c7981','941c88f8-0267-44e9-b0dd-473930e7d327',84,'image',NULL,'book/27-patient-os/fde8951a-086d-4810-9b6b-d58bed0a18be-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('23d721b1-eefc-4e26-8d8e-9981de596231','941c88f8-0267-44e9-b0dd-473930e7d327',85,'text','Ban quản lý phòng khám theo dõi độ bám đuổi của chặng Pre-Visit Care thông qua chỉ số **Tỷ lệ Hủy lịch và Bùng hẹn (No-Show Rate - NSR)** hằng tuần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5efa8da7-af0f-46d3-9cfe-5eb7da559e8f','941c88f8-0267-44e9-b0dd-473930e7d327',86,'text','NSR (\\%) = \\left( \\frac{\\text{Số lượng ca đặt lịch bị hủy sát giờ hoặc khách không đến thực tế}}{\\text{Tổng số lượng lịch hẹn nằm ở trạng thái Confirmed trong tuần}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bfbc254-d1ca-4bc6-b7c3-22c872d21824','941c88f8-0267-44e9-b0dd-473930e7d327',87,'text','- **Ngưỡng mục tiêu vận hành chuẩn:** Chỉ số NSR bắt buộc phải kiểm soát ở mức **<**** 10%**.- **Hành động sửa sai vĩ mô:** Nếu chỉ số NSR \\ge 15\\%, Quản lý phòng khám phải kiểm tra lại camera và lịch sử chat để xác định nguyên nhân: Do nhân sự quên không gửi tin nhắn nhắc hẹn chặn cuối, hay do khâu Sales Online chốt lịch ảo khi khách hàng chưa thực sự sẵn sàng về mặt tâm lý và thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d8ecda0b-d041-4cb8-91ce-92d1cbf973ca','27-patient-os','d2881fd9-cee6-4f40-ac50-07a3bdd28fbe',3,'MODULE 2: IN-CLINIC EXPERIENCE OS - HỆ THỐNG QUẢN TRỊ TRẢI NGHIỆM THỰC ĐỊA TẠI PHÒNG KHÁM','module-2-in-clinic-experience-os-he-thong-quan-tri-trai-nghiem-thuc-ia-tai-phong',41,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('78861d70-cbc0-4c02-abd4-208990d9fbeb','27-patient-os','d8ecda0b-d041-4cb8-91ce-92d1cbf973ca',4,'Tư Duy Cốt Lõi: Trải Nghiệm Toàn Diện Thay Thế Cho Sự Phụ Thuộc Chuyên Môn Đơn Lẻ','tu-duy-cot-loi-trai-nghiem-toan-dien-thay-the-cho-su-phu-thuoc-chuyen-mon-on-le',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('acb9cc67-c40d-4de3-b63b-e0f00f621591','78861d70-cbc0-4c02-abd4-208990d9fbeb',88,'text','Chuyên môn giỏi là điều kiện bắt buộc, nhưng không phải yếu tố duy nhất giữ chân bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('427d15b7-55b3-4c24-b2e7-6e513f6f34f8','78861d70-cbc0-4c02-abd4-208990d9fbeb',89,'text','Phần lớn bệnh nhân không đủ chuyên môn để đánh giá chất lượng kỹ thuật điều trị. Thay vào đó, họ ghi nhớ toàn bộ trải nghiệm từ lúc bước vào phòng khám cho đến sau khi hoàn tất điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2e8e33e-57e2-41e8-8e2d-ff3eab488200','78861d70-cbc0-4c02-abd4-208990d9fbeb',90,'text','Vì vậy, Patient OS tập trung chuẩn hóa mọi điểm chạm trong hành trình bệnh nhân, từ đón tiếp, tư vấn, điều trị đến chăm sóc sau điều trị, nhằm tạo ra cảm giác an tâm, được thấu hiểu và được đồng hành lâu dài.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4adc5c8-3348-4f75-ab78-f4d2e298eb89','78861d70-cbc0-4c02-abd4-208990d9fbeb',91,'text','**Bệnh nhân không chỉ nhớ mình được điều trị như thế nào. Họ nhớ mình được đối xử như thế nào.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ca23a864-de87-4980-a222-3814ef666bb1','27-patient-os','d8ecda0b-d041-4cb8-91ce-92d1cbf973ca',4,'Tám Tiêu Chuẩn Vàng Vận Hành Tại Phòng Khám (Experience Standards)','tam-tieu-chuan-vang-van-hanh-tai-phong-kham-experience-standards',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('053d7460-39d1-43da-950f-1cf472f21205','ca23a864-de87-4980-a222-3814ef666bb1',92,'text','Để toàn bộ nhân sự trực sàn (Lễ tân, Phụ tá, Bác sĩ) có chung một thước đo hành vi, hệ thống quy định nghiêm ngặt 8 tiêu chuẩn cứng dưới đây:',NULL,NULL,NULL,NULL,NULL);
