INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fa0a79fb-6b45-4883-950e-7d62d5caf57a','27-patient-os','d8ecda0b-d041-4cb8-91ce-92d1cbf973ca',4,'Quy Trình  Điều Phối Khách Thực Địa','quy-trinh-ieu-phoi-khach-thuc-ia',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db883b14-fc5c-4289-98d1-39d2d18ab951','fa0a79fb-6b45-4883-950e-7d62d5caf57a',94,'text','Mỗi bệnh nhân khi đến nha khoa sẽ được điều phối qua một quy trình 5 bước nhằm đảm bảo trải nghiệm nhất quán, liền mạch và chuyên nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('605377e3-821b-4687-b252-028c77646c1d','fa0a79fb-6b45-4883-950e-7d62d5caf57a',95,'text','**Check-in → Escort → Consultation → Treatment → Checkout**',NULL,NULL,NULL,NULL,NULL);
