INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('faf9a0e2-99ef-443c-9db1-abf6594aefda','fa0a79fb-6b45-4883-950e-7d62d5caf57a',98,'text','Lễ tân chủ động chào đón bệnh nhân, xác nhận lịch hẹn và cập nhật trạng thái hồ sơ trên CRM sang **Arrived**.',NULL,NULL,NULL,NULL,NULL);
