INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('98fd5b09-6b86-49cd-ac6e-4c99e9a77826','fa0a79fb-6b45-4883-950e-7d62d5caf57a',101,'text','Bệnh nhân được hướng dẫn đến khu vực chụp phim, phòng khám hoặc khu vực chờ phù hợp. Mọi trường hợp chờ quá thời gian tiêu chuẩn đều được chủ động thông báo và giải thích.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('88c24c75-68b9-42ea-8b3d-4df81cba74da','fa0a79fb-6b45-4883-950e-7d62d5caf57a',102,'text','**Bước 3. Consultation **',NULL,NULL,NULL,NULL,NULL);
