INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62aeab8d-22ac-4ff2-bd21-cda0601aad14','fa0a79fb-6b45-4883-950e-7d62d5caf57a',104,'text','Bác sĩ phân tích tình trạng răng miệng dựa trên dữ liệu lâm sàng, giải thích các lựa chọn điều trị bằng ngôn ngữ dễ hiểu. Kế hoạch điều trị, chi phí và lộ trình thực hiện được trình bày rõ ràng để bệnh nhân đưa ra quyết định.',NULL,NULL,NULL,NULL,NULL);
