INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8179ef43-c251-475b-a9af-596f1749b17b','fa0a79fb-6b45-4883-950e-7d62d5caf57a',108,'text','**Bước 5. Checkout**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('460a3265-75dc-4f28-80ae-ec39a783257d','fa0a79fb-6b45-4883-950e-7d62d5caf57a',109,'text','**Bàn Giao Và Hẹn Tái Khám**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f95af65a-815d-4d46-b51b-ce7dce3cf747','fa0a79fb-6b45-4883-950e-7d62d5caf57a',110,'text','Bệnh nhân được hướng dẫn chăm sóc sau điều trị, hoàn tất thủ tục thanh toán, nhận thông tin bảo hành và được đặt lịch tái khám hoặc chăm sóc định kỳ trên hệ thống CRM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d430179-b2f4-4ebb-80ee-656d6b6d94ff','fa0a79fb-6b45-4883-950e-7d62d5caf57a',111,'text','Đây là chu trình vận hành tiêu chuẩn giúp đảm bảo mọi bệnh nhân đều nhận được trải nghiệm nhất quán từ lúc bước vào phòng khám cho đến khi hoàn tất điều trị.',NULL,NULL,NULL,NULL,NULL);
