INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('87c24f37-82d4-48f7-a455-312216a0754b','d1299800-7dc3-4438-97c8-c2647abc8493',112,'text','Cuối mỗi ngày ca trực, Quản lý phòng khám thực hiện kiểm toán ngẫu nhiên hồ sơ khách hàng để tích duyệt chất lượng vận hành sàn theo bộ tiêu chuẩn 9 điểm neo:',NULL,NULL,NULL,NULL,NULL);
