INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bd91b435-9c52-4c71-953c-e868c8dc51f2','27-patient-os','7b125be2-3ccc-4ebe-ae4e-53c7c725ecca',4,'Tư Duy Cốt Lõi: Đánh Chặn Rủi Ro Lâm Sàng, Bảo Vệ Bệnh Nhân Từ Xa','tu-duy-cot-loi-anh-chan-rui-ro-lam-sang-bao-ve-benh-nhan-tu-xa',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f483475a-89b2-4765-aa64-7208b6fed216','bd91b435-9c52-4c71-953c-e868c8dc51f2',114,'text','Mấy ngày đầu tự chăm sóc tại nhà là lúc tâm lý bệnh nhân dễ dao động nhất. Khi thuốc tê tan, các hiện tượng sưng, đau, ê buốt xuất hiện. Nếu phòng khám im lặng, người bệnh rất dễ hoang mang, tự lên mạng tìm thông tin sai lệch và quay sang nghi ngờ chất lượng điều trị của bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('198fac9a-9fff-440d-a4aa-6fcecba2c6a1','bd91b435-9c52-4c71-953c-e868c8dc51f2',115,'text','Phân hệ **Treatment Follow-up OS** được thiết lập như một quy chuẩn bắt buộc để số hóa khâu hậu phẫu. Việc chủ động hỏi thăm không đơn thuần là phép lịch sự, mà là hàng rào kỹ thuật giúp đội ngũ lâm sàng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e7f5c6f4-dd9f-4947-9279-1a6f5d2a7e85','bd91b435-9c52-4c71-953c-e868c8dc51f2',116,'text','- **Giám sát chặt chẽ** tiến trình phục hồi của bệnh nhân từ xa.- **Phát hiện sớm** các dấu hiệu bất thường để đưa ra chỉ dẫn y khoa kịp thời.- **Bảo vệ an toàn tuyệt đối** và giữ vững lòng tin của khách hàng sau khi rời ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96c75370-dedb-48cd-b8d1-6b9d20cdf688','bd91b435-9c52-4c71-953c-e868c8dc51f2',117,'text','**Cốt lõi vận hành:** Đừng để bệnh nhân phải cô đơn đối mặt với cơn đau tại nhà. Sự chủ động của phòng khám chính là liều thuốc an thần hiệu quả nhất giúp khách hàng hoàn toàn an tâm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a9f037ae-565f-4594-912e-39016e442931','27-patient-os','7b125be2-3ccc-4ebe-ae4e-53c7c725ecca',4,'Năm Mục Tiêu Vận Hành Chiến Lược','nam-muc-tieu-van-hanh-chien-luoc',49,'[]');
