INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b208d68b-0013-4606-a843-6d6970961e97','49c187d2-d376-4877-bec3-b691e2fb33e9',120,'text','Các kịch bản tin nhắn được thiết kế ngắn gọn, đi thẳng vào vấn đề chuyên môn, sử dụng ngôn từ lịch sự, gần gũi và rõ ý:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('69dd6d64-d8e1-4f69-a4f0-5f521650c061','49c187d2-d376-4877-bec3-b691e2fb33e9',121,'text','Mẫu tin nhắn gửi sau 2 - 4 giờ (Áp dụng cho các ca can thiệp thủ thuật hằng ngày)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b3bb6f18-c90b-4c26-997b-86c4e112d91f','49c187d2-d376-4877-bec3-b691e2fb33e9',122,'text','**Chào anh/chị [Tên_Khách_Hàng],**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('45101f77-e129-4138-ba52-97960e3a31ce','49c187d2-d376-4877-bec3-b691e2fb33e9',123,'text','Em là [Tên_Nhân_Sự] từ nha khoa Thích Làm Răng Hà Nội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a6c3f79-e4ac-49e0-af79-a399acb4e2ae','49c187d2-d376-4877-bec3-b691e2fb33e9',124,'text','Hiện tại thuốc tê ở vùng răng điều trị của anh/chị chắc đã hết tác dụng hoàn toàn. Anh/chị có cảm thấy bị đau nhiều hay gặp bất tiện gì không ạ?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44249075-e68d-45aa-9134-8cd1e522d537','49c187d2-d376-4877-bec3-b691e2fb33e9',125,'text','Anh/chị lưu ý giúp em uống thuốc đúng theo đơn Bác sĩ Vinh đã kê để kiểm soát cơn đau tốt nhất nhé. Nếu có tình trạng rỉ máu hoặc cảm giác khó chịu lớn, anh/chị nhắn ngay tại đây để em báo Bác sĩ hỗ trợ mình kịp thời ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9a0a00ed-32ba-4829-b30c-2387ed82649b','49c187d2-d376-4877-bec3-b691e2fb33e9',126,'text','Mẫu tin nhắn gửi sau 24 giờ (Kiểm tra tiến trình ăn nhai và phản ứng sinh học)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9749b245-4693-4c68-9955-c6d3867a102c','49c187d2-d376-4877-bec3-b691e2fb33e9',127,'text','**Chào anh/chị [Tên_Khách_Hàng],**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7207e27b-bdbe-4652-8999-20d3ede2209c','49c187d2-d376-4877-bec3-b691e2fb33e9',128,'text','Phòng khám nhắn tin để kiểm tra tình trạng răng của anh/chị sau 1 ngày điều trị ạ. Hôm nay vùng răng của mình có bị sưng hay ê buốt nhiều không, và anh/chị ăn uống các món mềm có gặp khó khăn gì không ạ?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e93620d7-a450-4404-8f47-574b27f528ce','49c187d2-d376-4877-bec3-b691e2fb33e9',129,'text','Nếu vùng má có dấu hiệu sưng nhẹ, anh/chị tiếp tục duy trì chườm mát bên ngoài giúp em nhé. Anh/chị cập nhật lại tình trạng hiện tại để bên em theo dõi sát sao hồ sơ cho mình nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f05b9f6f-89a6-4d41-9114-f56eae65bff1','49c187d2-d376-4877-bec3-b691e2fb33e9',130,'text','Mẫu tin nhắn gửi sau 7 ngày (Nhắc lịch hẹn cắt chỉ hoặc kiểm tra khớp cắn)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39e7a441-28db-40e5-b166-de00a5c20eb9','49c187d2-d376-4877-bec3-b691e2fb33e9',131,'text','**Chào anh/chị [Tên_Khách_Hàng],**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6fd6448f-14f8-4b9c-af8b-7b21213fbdc7','49c187d2-d376-4877-bec3-b691e2fb33e9',132,'text','Vết thương răng của anh/chị đến hôm nay đã tròn 1 tuần và bắt đầu bước vào giai đoạn lành thương ổn định rồi ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b7cd733-629b-4a80-8b94-bf38b335b0f2','49c187d2-d376-4877-bec3-b691e2fb33e9',133,'text','Theo phác đồ điều trị, vào lúc **[Giờ_Hẹn] ngày [Ngày/Tháng]**, anh/chị có lịch hẹn quay lại phòng khám để Bác sĩ kiểm tra tốc độ liền nướu (và thực hiện cắt chỉ nhẹ nhàng nếu có).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d57cccb-bdef-45bc-b894-ed0202ccf130','49c187d2-d376-4877-bec3-b691e2fb33e9',134,'text','Anh/chị xác nhận lại giúp em lịch hẹn này để bộ phận Lễ tân chuẩn bị phòng điều trị chu đáo cho mình nhé ạ.',NULL,NULL,NULL,NULL,NULL);
