INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7dd94818-2763-4841-a0f3-e4139aca489b','27-patient-os','d186fb61-8044-4198-bc23-e97f92856a31',4,'Tư Duy Cốt Lõi: Bảo Vệ Kết Quả Điều Trị Và Tối Ưu Hiệu Suất Ghế Trống','tu-duy-cot-loi-bao-ve-ket-qua-ieu-tri-va-toi-uu-hieu-suat-ghe-trong',54,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10793842-4cee-413f-bdde-3fb026c44547','7dd94818-2763-4841-a0f3-e4139aca489b',136,'text','Nhiều phòng khám nha khoa hiện nay thường bỏ trống khâu nhắc lịch tái khám, hoặc chỉ thực hiện một cách ngẫu hứng khi phòng khám vắng khách. Lỗi vận hành này trực tiếp gây ra 4 tổn thất lớn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('69c528ef-c859-4a36-8df4-8f76fdbc24f4','7dd94818-2763-4841-a0f3-e4139aca489b',137,'text','- **Mất dòng doanh thu ổn định** từ các dịch vụ chăm sóc định kỳ.- **Bỏ lỡ thời điểm vàng** để phát hiện sớm các vấn đề phát sinh sau điều trị.- **Mất cơ hội tư vấn bổ sung** các dịch vụ phù hợp tiếp theo (như tẩy trắng răng sau khi tháo niềng, hoặc làm răng sứ sau khi điều trị tủy).- **Làm phai nhạt mối quan hệ** dài hạn với bệnh nhân, tạo điều kiện để họ chuyển sang phòng khám đối thủ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f7536a8-945f-45bf-8c3a-134008e9ead0','7dd94818-2763-4841-a0f3-e4139aca489b',138,'text','Hệ thống **Recall & Recheck System** được xây dựng như một quy trình bắt buộc để duy trì tỷ lệ lấp đầy lịch ghế nha ổn định hằng tuần bằng tệp khách hàng cũ, đồng thời đảm bảo tính liên tục của phác đồ y khoa.',NULL,NULL,NULL,NULL,NULL);
