INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('03b80ed3-01b8-48ac-9f38-beb4e0538b72','6421cf60-fd0a-42fe-81d4-58603b3edc64',144,'text','Bộ phận CSKH vận hành bộ lọc trên CRM để kết xuất toàn bộ danh sách bệnh nhân có ngày hẹn tái khám định kỳ rơi vào tuần kế tiếp.',NULL,NULL,NULL,NULL,NULL);
