INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9727fdb6-6ad1-4d26-a4a2-44a88459bb7d','6421cf60-fd0a-42fe-81d4-58603b3edc64',147,'text','Hệ thống gửi tin nhắn cá nhân hóa qua Zalo OA đề xuất trực tiếp ngày và các khung giờ trống phù hợp với từng nhóm dịch vụ của khách.',NULL,NULL,NULL,NULL,NULL);
