INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3134b998-f6e5-49fb-91de-c32c2a7382b5','6421cf60-fd0a-42fe-81d4-58603b3edc64',150,'text','Đối với các hồ sơ chưa phản hồi tin nhắn, nhân sự thực hiện cuộc gọi trực tiếp để thăm hỏi tình trạng và hỗ trợ giữ chỗ, cập nhật trạng thái lịch sang `Confirmed` trên CRM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45ed0428-0324-47e6-bdaa-9aa4729464e2','27-patient-os','d186fb61-8044-4198-bc23-e97f92856a31',4,'Bộ Mẫu Kịch Bản Tin Nhắn Chuẩn Hóa Qua Zalo OA','bo-mau-kich-ban-tin-nhan-chuan-hoa-qua-zalo-oa',57,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9833718e-d35f-4908-8633-6e6891585286','45ed0428-0324-47e6-bdaa-9aa4729464e2',151,'text','Các kịch bản tin nhắn được thiết kế rõ ý, ngắn gọn, đi thẳng vào quyền lợi y khoa của khách hàng và không dùng từ ngữ rườm rà:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b4ae72cb-7432-4c81-80b8-143df5f35c62','45ed0428-0324-47e6-bdaa-9aa4729464e2',152,'text','Mẫu 1: Nhắc lịch tái khám chung (Áp dụng cho Cạo vôi, Trám răng, Tổng quát)',NULL,NULL,NULL,NULL,NULL);
