INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02ddd8f7-16ea-4974-bcf1-c88b68c7b0dd','45ed0428-0324-47e6-bdaa-9aa4729464e2',154,'text','Em là [Tên_Nhân_Sự] từ nha khoa Thích Làm Răng Hà Nội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdbfe097-764c-4d60-ae67-14872ec89a87','45ed0428-0324-47e6-bdaa-9aa4729464e2',155,'text','Theo lịch trình chăm sóc răng miệng định kỳ, đã đến thời gian anh/chị cần quay lại phòng khám để bác sĩ kiểm tra và đánh giá lại tình trạng răng hiện tại sau [6 tháng] điều trị ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04c5de94-85f8-4238-a9ea-576347216b21','45ed0428-0324-47e6-bdaa-9aa4729464e2',156,'text','Việc kiểm tra định kỳ này rất quan trọng để giúp làm sạch mảng bám sâu và phát hiện sớm các vấn đề răng miệng nếu có.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5a3c3e20-c552-4387-a88c-7a7ead969f0d','45ed0428-0324-47e6-bdaa-9aa4729464e2',157,'text','Tuần này phòng khám đang có các khung giờ trống vào **[Thứ_Trong_Tuần], ngày [Ngày/Tháng]** lúc **[Giờ_Trống]**. Anh/chị xem có tiện sắp xếp thời gian ghé qua kiểm tra không, nhắn lại để em đặt lịch chu đáo nhé ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('01516e86-1c5a-4a47-b724-1f02e4717cc2','45ed0428-0324-47e6-bdaa-9aa4729464e2',158,'text','Mẫu 2: Nhắc lịch tái khám chuyên sâu (Áp dụng cho Răng sứ, Implant, Nha chu)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3379a320-45fa-47c3-9516-768b027552be','45ed0428-0324-47e6-bdaa-9aa4729464e2',159,'text','**Chào anh/chị [Tên_Khách_Hàng],**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('01b94947-1eea-4966-b728-0c59800ff473','45ed0428-0324-47e6-bdaa-9aa4729464e2',160,'text','Theo phác đồ theo dõi sau điều trị [Dịch_Vụ], hiện tại đã đến chu kỳ tái khám kiểm tra định kỳ của anh/chị để Bác sĩ đánh giá độ ổn định của răng và chức năng ăn nhai thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ebeb71ce-05cb-4128-8a8d-bff0b62821d4','45ed0428-0324-47e6-bdaa-9aa4729464e2',161,'text','Buổi hẹn kiểm tra này nằm trong chính sách theo dõi định kỳ của phòng khám để đảm bảo hiệu quả điều trị tốt nhất cho anh/chị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c58d3141-b744-4135-bb49-9b62f2e617db','45ed0428-0324-47e6-bdaa-9aa4729464e2',162,'text','Phòng khám đã chuẩn bị sẵn khung giờ ưu tiên cho anh/chị vào lúc **[Giờ_Hẹn] ngày [Ngày/Tháng]**. Anh/chị xác nhận lại giúp em lịch hẹn này để bên em giữ chỗ ghế nha cho mình nhé ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('168a2751-f45c-43c5-a3f2-75d4b60ee6c9','27-patient-os','d186fb61-8044-4198-bc23-e97f92856a31',4,'Chỉ Số Đo Lường Hiệu Quả Vận Hành (KPI)','chi-so-o-luong-hieu-qua-van-hanh-kpi',58,'[]');
