INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3f720d93-1027-4ce7-bd10-9c4ea58e746b','27-patient-os','e557c100-1705-48de-b70d-8317703f0310',4,'Tư Duy Cốt Lõi: Thu Hoạch Lòng Tin Đúng Thời Điểm (Peak Wow)','tu-duy-cot-loi-thu-hoach-long-tin-ung-thoi-iem-peak-wow',60,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d7ffd85-948f-4ac5-a2be-2702e06ce331','3f720d93-1027-4ce7-bd10-9c4ea58e746b',164,'text','Review không phải là kết quả của sự nài nỉ hay ép buộc. Một đánh giá chất lượng chỉ xuất hiện khi bệnh nhân thực sự hài lòng và được mời chia sẻ đúng thời điểm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d597eea7-38d7-4b3d-8675-d27a92abaeb7','3f720d93-1027-4ce7-bd10-9c4ea58e746b',165,'text','Thời điểm tốt nhất để xin review là khi bệnh nhân vừa hoàn thành điều trị thành công, vừa nhận thấy sự cải thiện rõ rệt hoặc vừa bày tỏ sự hài lòng với trải nghiệm tại phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1e83bc22-a4fc-4eb9-8a8e-2f35685ff14b','3f720d93-1027-4ce7-bd10-9c4ea58e746b',166,'text','Ngược lại, nếu xin đánh giá khi bệnh nhân còn đau, còn lo lắng hoặc đang có trải nghiệm chưa trọn vẹn, khả năng nhận được phản hồi tích cực sẽ giảm đáng kể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('67460393-af7f-4c13-a077-429425791d77','3f720d93-1027-4ce7-bd10-9c4ea58e746b',167,'text','Vì vậy, Patient OS không xem review là một hoạt động ngẫu hứng mà là một quy trình được thiết kế và đo lường bài bản. Hệ thống giúp xác định đúng bệnh nhân, đúng thời điểm và đúng cách tiếp cận để chuyển hóa sự hài lòng thành những đánh giá chân thực, góp phần xây dựng uy tín và niềm tin cho phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dccb71a3-b76d-4ff0-8673-e9beb459e1d4','3f720d93-1027-4ce7-bd10-9c4ea58e746b',168,'text','**Triết lý vận hành:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('71c1125d-ae93-4bd0-a691-1ffbae9e4211','3f720d93-1027-4ce7-bd10-9c4ea58e746b',169,'text','Đừng xin review từ mọi bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8648cb1-0650-4c75-8bb8-c85d5391c4e1','3f720d93-1027-4ce7-bd10-9c4ea58e746b',170,'text','Hãy tạo ra trải nghiệm đủ tốt để bệnh nhân tự nguyện chia sẻ và giới thiệu phòng khám cho người khác.',NULL,NULL,NULL,NULL,NULL);
