INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f44674a-8d5e-4fac-ba3e-9dbce0cfe295','60b16435-b7c9-400e-b11e-d8d5fde5d5dc',176,'text','Ngôn từ giao tiếp cần giữ sự chuyên nghiệp, lịch sự, đi thẳng vào vấn đề và tạo sự thoải mái cho người bệnh',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8b94904e-bfde-441d-9a26-a6484b33da3b','60b16435-b7c9-400e-b11e-d8d5fde5d5dc',177,'text','Kịch bản thoại trực tiếp tại quầy lễ tân (Khi khách hàng vừa khen ngợi dịch vụ)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bd31961-7d0d-4707-9e0a-145ee7e82c35','60b16435-b7c9-400e-b11e-d8d5fde5d5dc',178,'text','"Dạ em cảm ơn anh/chị rất nhiều vì đã tin tưởng và dành lời khen cho ekip của Bác sĩ Vinh ngày hôm nay ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('321b9ceb-d51e-4a1e-ae03-7424807b0956','60b16435-b7c9-400e-b11e-d8d5fde5d5dc',179,'text','Nếu anh/chị cảm thấy thực sự hài lòng với trải nghiệm điều trị vừa rồi, anh/chị có thể dành giúp phòng khám khoảng 1 phút để để lại một đánh giá ngắn trên trang Google Maps được không ạ?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a09e092a-22a9-453d-b6d6-85f9036cb7d6','60b16435-b7c9-400e-b11e-d8d5fde5d5dc',180,'text','Những chia sẻ thực tế của anh/chị rất có giá trị, giúp cho những bệnh nhân khác có thêm sự an tâm và niềm tin khi lựa chọn nơi điều trị răng giống như mình ạ. Anh/chị quét mã QR ngay tại quầy này là được nhé ạ."',NULL,NULL,NULL,NULL,NULL);
