INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c669fb1-3b2b-4358-a72b-2624460533be','60b16435-b7c9-400e-b11e-d8d5fde5d5dc',184,'text','Phòng khám rất vui khi nhận được phản hồi của anh/chị về việc ăn nhai đã ổn định và không còn ê buốt nữa ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f2c0cd8e-f19f-4155-91d6-8167fff937be','60b16435-b7c9-400e-b11e-d8d5fde5d5dc',185,'text','Nếu anh/chị hài lòng với kết quả điều trị và sự chăm sóc của đội ngũ y bác sĩ, anh/chị có thể dành tặng phòng khám một đánh giá ngắn kèm điểm số 5 sao trên Google Maps theo đường link này được không ạ: **[Link_Google_Maps]**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b80cbf4a-35b7-44f4-bcd8-c69545120b88','60b16435-b7c9-400e-b11e-d8d5fde5d5dc',186,'text','Mỗi đánh giá tích cực của anh/chị chính là nguồn động lực rất lớn để tập thể phòng khám tiếp tục nâng cao chất lượng dịch vụ hằng ngày. Chúc anh/chị có một ngày làm việc hiệu quả!',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b5a7d8c9-fac9-4537-a8c7-3f1edd736110','27-patient-os','e557c100-1705-48de-b70d-8317703f0310',4,'Chỉ Số Kiểm Soát Vận Hành (KPI)','chi-so-kiem-soat-van-hanh-kpi',65,'[]');
