INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e826046-58f8-4d17-8fe5-b1d76e1cca70','b5a7d8c9-fac9-4537-a8c7-3f1edd736110',188,'text','**Mantra điều hành Review Activation OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e28638f9-16f9-4115-9294-359ea406040d','b5a7d8c9-fac9-4537-a8c7-3f1edd736110',189,'text','*"Đừng đợi khách hàng tự nhớ để khen ngợi bạn trên internet. Hãy chủ động tạo ra một trải nghiệm tốt tại phòng khám, chọn đúng thời điểm họ hạnh phúc nhất để hướng dẫn họ chia sẻ câu chuyện của mình. Sự thật từ người bệnh chính là vũ khí truyền thông tử tế và mạnh mẽ nhất."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a347ca22-823c-43ef-8a12-f813880fc74a','27-patient-os','d2881fd9-cee6-4f40-ac50-07a3bdd28fbe',3,'MODULE 6: TESTIMONIAL COLLECTION OS - HỆ THỐNG THU THẬP VÀ ĐÓNG GÓI CÂU CHUYỆN BỆNH NHÂN','module-6-testimonial-collection-os-he-thong-thu-thap-va-ong-goi-cau-chuyen-benh-',66,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4033e514-6883-470e-93cb-0e83f433d1b7','27-patient-os','a347ca22-823c-43ef-8a12-f813880fc74a',4,'Tư Duy Cốt Lõi: Sức Mạnh Thuyết Phục Từ Những Hành Trình Thực Tế','tu-duy-cot-loi-suc-manh-thuyet-phuc-tu-nhung-hanh-trinh-thuc-te',67,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76604944-42bf-4637-bc12-3a1c2ba0f8ee','4033e514-6883-470e-93cb-0e83f433d1b7',190,'text','Một đánh giá ngắn (Review) trên Google Maps rất có giá trị để tối ưu hóa thuật toán hiển thị, nhưng một **Câu chuyện thực tế (Testimonial)** mới là vũ khí tối thượng để chuyển hóa tâm lý khách hàng. Bệnh nhân khi tìm hiểu các dịch vụ can thiệp sâu như Implant hay Chỉnh nha thường mang tâm lý sợ đau, sợ hỏng và sợ tốn chi phí lãng phí. Họ không tin lời quảng cáo của phòng khám, nhưng họ sẽ tin vào hành trình trải nghiệm của một người thật có cùng điểm đau với họ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('708abc9d-4325-4952-a538-3f03b8382743','4033e514-6883-470e-93cb-0e83f433d1b7',191,'text','Một Testimonial tiêu chuẩn tại nha khoa Dental Empire OS không đơn thuần là một lời khen ngợi suông. Nó là một tài sản truyền thông có cấu trúc, chứa đựng đầy đủ **bối cảnh khó khăn ban đầu, diễn biến trải nghiệm trên ghế nha và kết quả lột xác mặt sinh học lẫn sự tự tin**. Khi khách hàng mục tiêu tại Hà Nội đọc hoặc xem được những tư liệu này, họ sẽ nhìn thấy hình ảnh của chính mình trong đó, từ đó chủ động gỡ bỏ rào cản phòng thủ tâm lý để đặt lịch hẹn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c4a3f537-5f23-4a19-81b2-5bc0dcd2b666','27-patient-os','a347ca22-823c-43ef-8a12-f813880fc74a',4,'Danh Mục 8 Hình Thức Đóng Gói Testimonial (The Trust Assets Layer)','danh-muc-8-hinh-thuc-ong-goi-testimonial-the-trust-assets-layer',68,'[]');
