INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('767b1c1c-a248-4fa7-bf04-c0d14d359e4c','3f469e54-a22e-4f78-87c5-e1a047c398b4',194,'text','Để tránh tình trạng nhân sự sản xuất nội dung bị lan man, thiếu trọng tâm, mọi Testimonial bắt buộc phải được biên tập theo đúng cấu trúc tuyến tính 4 chặng:',NULL,NULL,NULL,NULL,NULL);
