INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4c85d291-e625-4424-a4ee-feafa098a4c5','27-patient-os','a347ca22-823c-43ef-8a12-f813880fc74a',4,'Bộ Câu Hỏi Gợi Mở Tâm Lý Khi Phỏng Vấn Trực Tiếp','bo-cau-hoi-goi-mo-tam-ly-khi-phong-van-truc-tiep',70,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4903a7b-22ff-465d-82b5-186f0994491b','4c85d291-e625-4424-a4ee-feafa098a4c5',196,'text','Khi tiến hành thu thập câu chuyện tại phòng VIP, nhân sự CSKH tuyệt đối không được đọc kịch bản như trả bài. Hãy sử dụng 6 câu hỏi mở có ngôn từ gần gũi dưới đây để khơi gợi dòng cảm xúc tự nhiên của người bệnh:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a54cbd7d-79bf-48a9-8b3d-26f901d71601','4c85d291-e625-4424-a4ee-feafa098a4c5',197,'text','- *"Trước khi quyết định đến với phòng khám mình, điều gì khiến anh/chị lo lắng hoặc sợ hãi nhất ạ?"* (Khai thác điểm đau và nỗi sợ chung của thị trường).- *"Giữa rất nhiều nha khoa tại Hà Nội, lý do thực tế nào đã khiến anh/chị tin tưởng và lựa chọn nha khoa Thích Làm Răng?"* (Tìm ra lợi thế cạnh tranh cốt lõi dưới góc nhìn của khách).- *"Trong suốt quá trình Bác sĩ thực hiện thao tác trên ghế nha, anh/chị thấy mức độ đau và ê buốt có giống như những gì mình lo sợ trước đó không?"* (Hóa giải nỗi sợ đau sinh học cho người xem).- *"Điều gì trong cách phục vụ của Bác sĩ Vinh và các bạn trợ thủ tại đây khiến anh/chị cảm thấy thoải mái và hài lòng nhất?"* (Làm nổi bật yếu tố thấu cảm và sự tử tế của dịch vụ).- *"Sau khi đã hoàn tất toàn bộ quá trình điều trị, cuộc sống sinh hoạt ăn uống hay sự tự tin trong giao tiếp của anh/chị đã thay đổi tích cực như thế nào rồi ạ?"* (Nhấn mạnh vào kết quả lột xác và giá trị nhận lại).- *"Nếu có người thân hoặc bạn bè cũng đang gặp các vấn đề về răng và có nỗi sợ giống mình trước đây, anh/chị có sẵn sàng giới thiệu họ qua phòng khám mình không ạ?"* (Kích hoạt lời bảo chứng uy tín công khai).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0d23b78a-d84c-4b9d-bac2-cb6af7cd7329','27-patient-os','a347ca22-823c-43ef-8a12-f813880fc74a',4,'Quy Trình Thu Hoạch Và Chuyển Giao Tài Sản (The Capture Pipeline)','quy-trinh-thu-hoach-va-chuyen-giao-tai-san-the-capture-pipeline',71,'[]');
