INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('119f3e2c-f81d-4e41-94ca-cc9fa1159368','0d23b78a-d84c-4b9d-bac2-cb6af7cd7329',199,'text','**Mantra điều hành Testimonial Collection OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78be94de-3dc8-46ca-91d4-c84e5fcf1c88','0d23b78a-d84c-4b9d-bac2-cb6af7cd7329',200,'text','*"Đừng bắt team Marketing phải cố gắng nghĩ ra những câu từ hoa mỹ để thuyết phục thị trường. Hãy trao cho họ những câu chuyện người thật, việc thật, những hành trình vượt qua nỗi sợ hãi và nụ cười hạnh phúc của bệnh nhân. Sự thật y khoa được kể bằng sự biết ơn của người bệnh chính là chất liệu truyền thông có sức mạnh chuyển đổi cao nhất."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('243b4d8e-d9c7-46dd-8506-0a2c254311f7','27-patient-os','d2881fd9-cee6-4f40-ac50-07a3bdd28fbe',3,'MODULE 7: RETENTION SYSTEM - HỆ THỐNG GIỮ CHÂN VÀ DUY TRÌ MỐI QUAN HỆ KHÁCH HÀNG DÀI HẠN','module-7-retention-system-he-thong-giu-chan-va-duy-tri-moi-quan-he-khach-hang-da',72,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('33ffe202-592b-4412-a04e-db738f734ccd','27-patient-os','243b4d8e-d9c7-46dd-8506-0a2c254311f7',4,'Tư Duy Cốt Lõi: Giảm Phụ Thuộc Vào Quảng Cáo Bằng Năng Lực Giữ Chân Khách Hàng','tu-duy-cot-loi-giam-phu-thuoc-vao-quang-cao-bang-nang-luc-giu-chan-khach-hang',73,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8079339d-239a-4030-9a7f-fda0e3d1754c','33ffe202-592b-4412-a04e-db738f734ccd',201,'text','Năng lực giữ chân bệnh nhân (Retention) là thước đo chính xác nhất cho sự bền vững của một phòng khám nha khoa. Chi phí để thu hút một khách hàng mới (CAC) tại thị trường Hà Nội ngày càng cao. Nếu phòng khám chỉ tập trung tìm kiếm khách hàng mới mà bỏ quên tệp bệnh nhân cũ, biên lợi nhuận ròng sẽ bị bào mòn nghiêm trọng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4bafbf67-8ee7-496a-87e4-8e6b1e0f410d','33ffe202-592b-4412-a04e-db738f734ccd',202,'text','Hệ thống **Retention System** được thiết lập nhằm duy trì sự kết nối chặt chẽ với bệnh nhân sau khi giao dịch đầu tiên kết thúc. Khi có hệ thống giữ chân tốt, phòng khám sẽ đạt được 3 mục tiêu thực tế:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('33260725-33b4-4347-b343-ecdfba69dd61','33ffe202-592b-4412-a04e-db738f734ccd',203,'text','- **Duy trì nguồn doanh thu ổn định** từ các dịch vụ lặp lại và nâng cấp.- **Tăng tỷ lệ lấp đầy lịch ghế trống** hằng tuần một cách chủ động.- **Xây dựng rào cản cạnh tranh tự nhiên** nhờ lòng tin sâu sắc của bệnh nhân cũ, khiến họ không chuyển sang các phòng khám khác.',NULL,NULL,NULL,NULL,NULL);
