INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39914bb7-7656-4da5-88b0-95162b4dd11a','2131ae47-4c58-4165-80cb-a280f26572de',207,'text','Các kịch bản tin nhắn được thiết kế ngắn gọn, lịch sự, đi thẳng vào thông tin hữu ích và quyền lợi của khách hàng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9582cdec-3ccd-4966-b39f-d4ba8e3cec1a','2131ae47-4c58-4165-80cb-a280f26572de',208,'text','Mẫu 1: Chúc mừng sinh nhật kèm quà tặng thiết thực',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04b76223-e17c-4f1a-8dad-fafda665266b','2131ae47-4c58-4165-80cb-a280f26572de',209,'text','**Chào anh/chị [Tên_Khách_Hàng],**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('abbde206-f9b4-435e-b268-e6757215ed27','2131ae47-4c58-4165-80cb-a280f26572de',210,'text','Nha khoa Thích Làm Răng chúc anh/chị có một ngày sinh nhật thật nhiều niềm vui và hạnh phúc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd7700be-fd9f-4fbb-967e-8a6a44864674','2131ae47-4c58-4165-80cb-a280f26572de',211,'text','Để đồng hành cùng nụ cười khỏe mạnh của anh/chị, phòng khám gửi tặng anh/chị một suất **Cạo vôi răng và Chăm sóc răng toàn diện hoàn toàn miễn phí** (hoặc giảm 50% chi phí dịch vụ Tẩy trắng răng thẩm mỹ).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00c83f36-e721-48e6-b8f9-74e4eed8d045','2131ae47-4c58-4165-80cb-a280f26572de',212,'text','Quà tặng có giá trị áp dụng trong vòng 30 ngày kể từ hôm nay. Anh/chị có thể nhắn lại khung giờ thuận tiện để em hỗ trợ đặt lịch hẹn trước chu đáo nhé ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('de184b0d-deb4-4b7f-80c4-24a72997ceab','2131ae47-4c58-4165-80cb-a280f26572de',213,'text','Mẫu 2: Gửi kiến thức hữu ích từ Bác sĩ (Tạo giá trị dài hạn)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9cf44b9c-9df9-45d6-968c-c54eefc2c95a','2131ae47-4c58-4165-80cb-a280f26572de',214,'text','**Chào anh/chị [Tên_Khách_Hàng],**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8568c4c6-e72d-4ae6-83da-70a99ca0587b','2131ae47-4c58-4165-80cb-a280f26572de',215,'text','Nhằm giúp anh/chị chăm sóc nụ cười tại nhà đúng cách sau khi [Niềng răng / Làm răng sứ], Bác sĩ Nguyễn Phước Vinh vừa hoàn thiện bài chia sẻ ngắn về: **"3 lưu ý quan trọng để bảo vệ men răng và tránh ê buốt khi ăn đồ lạnh"**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3e107f3a-01ae-4442-873c-80baae34c11d','2131ae47-4c58-4165-80cb-a280f26572de',216,'text','Anh/chị có thể xem nhanh bài viết hướng dẫn chi tiết tại đây để áp dụng hằng ngày nhé ạ: **[Link_Bài_Viết]**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e20cad08-931f-449c-b93f-9f8eedaa2a1e','2131ae47-4c58-4165-80cb-a280f26572de',217,'text','Nếu cần hỗ trợ thêm thông tin gì, anh/chị cứ nhắn lại cho em tại đây nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ed667ad2-41c9-42df-a134-178edc18048f','27-patient-os','243b4d8e-d9c7-46dd-8506-0a2c254311f7',4,'Mỏ Neo Toán Học: Chỉ Số Giữ Chân Bệnh Nhân (Patient Retention Rate - PRR)','mo-neo-toan-hoc-chi-so-giu-chan-benh-nhan-patient-retention-rate-prr',77,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0777fdc-489c-4fed-a483-68ec38b70bb8','ed667ad2-41c9-42df-a134-178edc18048f',218,'image',NULL,'book/27-patient-os/22aeefff-37d6-484b-bcf9-124c54edbf7a-img26.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('530a686d-c183-42b8-8a68-1c5cd22c2c5b','ed667ad2-41c9-42df-a134-178edc18048f',219,'text','**Mantra điều hành Retention System:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('760038df-7b8f-49c1-b0a3-20dd99b03856','ed667ad2-41c9-42df-a134-178edc18048f',220,'text','*"Một phòng khám phát triển bền vững không phải là nơi tìm được nhiều khách hàng mới nhất, mà là nơi biết trân trọng và giữ chân được nhiều bệnh nhân cũ nhất bằng sự tử tế và chu đáo xuyên suốt hành trình."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f9c5acb4-95dc-49c3-b7e9-dac992d6ddc3','27-patient-os',NULL,2,'27.8 Phân Tầng Bệnh Nhân Trong Patient OS (Patient Segmentation Framework)','278-phan-tang-benh-nhan-trong-patient-os-patient-segmentation-framework',78,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8e2cd016-558d-4419-9e97-efbf1a674c2f','27-patient-os','f9c5acb4-95dc-49c3-b7e9-dac992d6ddc3',3,'Tư Duy Cốt Lõi: Chăm Sóc Đúng Đối Tượng, Đúng Thời Điểm','tu-duy-cot-loi-cham-soc-ung-oi-tuong-ung-thoi-iem',79,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d6e1b1a-2b61-405c-9955-ed8edff830b0','8e2cd016-558d-4419-9e97-efbf1a674c2f',221,'text','Trong hệ điều hành Patient OS, không thể áp dụng một kịch bản chăm sóc chung cho tất cả mọi người. Mỗi nhóm bệnh nhân ở một giai đoạn khác nhau sẽ có những nhu cầu, nỗi sợ và kỳ vọng hoàn toàn khác biệt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('98f47a65-059a-437f-be24-037ca524ce17','8e2cd016-558d-4419-9e97-efbf1a674c2f',222,'text','Việc phân tầng bệnh nhân trên hệ thống CRM của nha khoa **Thích Làm Răng** giúp bộ máy quản trị tại Hà Nội:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6cbdc7f9-a94d-4b30-8e05-72530e1edf04','8e2cd016-558d-4419-9e97-efbf1a674c2f',223,'text','- **Tối ưu hóa nguồn lực nhân sự:** Tập trung chăm sóc sâu vào nhóm cần thiết, tránh spam tin nhắn gây phiền hà cho khách hàng.- **Cá nhân hóa trải nghiệm:** Đưa ra thông tin chỉ dẫn y khoa và kịch bản trò chuyện khớp đúng tâm lý thực tế của người bệnh.- **Kiểm soát rò rỉ đường ống:** Phát hiện sớm nguy cơ bỏ ngang điều trị hoặc lãng phí nguồn tài nguyên khách hàng cũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7d591057-7425-4a90-888a-8cbb6b2640aa','27-patient-os','f9c5acb4-95dc-49c3-b7e9-dac992d6ddc3',3,'Chi Tiết 3 Nhóm Phân Tầng Và Mục Tiêu Vận Hành','chi-tiet-3-nhom-phan-tang-va-muc-tieu-van-hanh',80,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f75352bb-fbe6-4a4c-abe6-6b42a3b96d9e','7d591057-7425-4a90-888a-8cbb6b2640aa',224,'text','**Nhóm A: New Patient (Bệnh nhân mới đến lần đầu)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c66abf3a-f5b1-4516-a344-96cf71593494','7d591057-7425-4a90-888a-8cbb6b2640aa',225,'text','- **Định nghĩa:** Khách hàng mới thực hiện lượt thăm khám, chụp phim và tư vấn đầu tiên tại phòng khám, chưa phát sinh hợp đồng điều trị lớn hoặc mới chỉ làm dịch vụ nhỏ.- **Mục tiêu vận hành:****Tạo ấn tượng tốt ban đầu:** Thiết lập mỏ neo lòng tin từ khâu tiếp đón ở sảnh đến khâu thăm khám trên ghế nha.- **Giải thích rõ ràng:** Bác sĩ giải thích bệnh lý trực quan qua phim chụp, bóc tách chi phí minh bạch để triệt tiêu sự đề phòng.- **Giảm lo lắng:** Chủ động xoa dịu nỗi sợ đau sinh học và sợ hỏng của khách hàng.- **Tăng tỷ lệ quay lại và chốt điều trị:** Chuyển đổi thành công từ hồ sơ thăm khám sang hồ sơ đồng ý theo phác đồ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57aceebe-097e-46aa-b8bf-c17dc25def13','7d591057-7425-4a90-888a-8cbb6b2640aa',226,'text','**Nhóm B: Active Treatment Patient (Bệnh nhân đang trong quá trình điều trị)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3a100fe7-1a9a-4c9c-a5de-e00e2fe0eedc','7d591057-7425-4a90-888a-8cbb6b2640aa',227,'text','- **Định nghĩa:** Bệnh nhân đã ký duyệt phác đồ và đang theo đuổi lộ trình điều trị nhiều giai đoạn (như niềng răng hằng tháng, chờ tích hợp xương Implant, hoặc đang chờ lắp phục hình sứ cố định).- **Mục tiêu vận hành:****Theo dõi sát tiến trình lành thương:** Giám sát chặt chẽ các phản ứng sinh học của cơ thể sau mỗi đợt can thiệp lâm sàng.- **Nhắc lịch đều đặn:** Đảm bảo bệnh nhân đi đúng chu kỳ y khoa để không làm kéo dài tổng thời gian điều trị.- **Giảm tỷ lệ bỏ ngang:** Phát hiện và can thiệp ngay khi bệnh nhân có dấu hiệu giãn lịch, trễ hẹn hoặc nản lòng.- **Đảm bảo kết quả đầu ra:** Giữ vững sự tin tưởng xuyên suốt hành trình trải nghiệm dài ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('928296b8-c837-4f20-8d14-ccb4b2359354','7d591057-7425-4a90-888a-8cbb6b2640aa',228,'text','**Nhóm C: Completed Treatment Patient (Bệnh nhân đã hoàn tất điều trị)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('df8a2695-5087-4cbb-bd31-3618ad4396b9','7d591057-7425-4a90-888a-8cbb6b2640aa',229,'text','- **Định nghĩa:** Bệnh nhân đã kết thúc toàn bộ phác đồ điều trị lâm sàng cốt lõi, ăn nhai ổn định và đã hoàn tất các nghĩa vụ thanh toán tài chính.- **Mục tiêu vận hành:****Xin Review công khai:** Chọn đúng thời điểm bệnh nhân hài lòng nhất để thu hoạch đánh giá 5 sao trên Google Maps.- **Lấy Testimonial chất lượng:** Đóng gói hình ảnh Before/After và video chia sẻ thực tế để làm chất liệu truyền thông sạch.- **Nhắc lịch tái khám định kỳ (Recall):** Đưa vào đường ống nhắc hẹn cạo vôi, kiểm tra răng 6 tháng/lần để bảo vệ kết quả.- **Kích hoạt luồng giới thiệu (Referral):** Trao thẻ đặc quyền để bệnh nhân chủ động đưa người thân, bạn bè đến phòng khám.- **Duy trì mối quan hệ trọn đời:** Biến khách hàng thành một phần của cộng đồng thân thiết, bảo chứng uy tín cho phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4814b07d-80a5-44f0-8776-fb23eb370c5f','7d591057-7425-4a90-888a-8cbb6b2640aa',230,'text','**Nhóm D: VIP Patient (Bệnh nhân có giá trị cao hoặc có ảnh hưởng)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d09c8d60-3440-4d30-89af-70293dd9acb5','7d591057-7425-4a90-888a-8cbb6b2640aa',231,'text','- **Định nghĩa:** Khách hàng sử dụng các gói dịch vụ phân khúc cao cấp (Implant toàn hàm, Chỉnh nha Invisalign toàn diện) hoặc những cá nhân có sức ảnh hưởng lớn trên mạng xã hội (KOLs, KOCs, Đối tác chiến lược).- **Mục tiêu vận hành:****Chăm sóc cá nhân hóa sâu:** Phục vụ tại phòng VIP riêng, có Trợ lý y khoa theo sát hỗ trợ 1-1.- **Tăng độ trung thành (Loyalty):** Thiết lập các đặc quyền chăm sóc và chính sách hậu mãi tối cao.- **Tạo Referral chất lượng:** Khai thác vòng tròn mối quan hệ cao cấp của khách để thu hút thêm tệp khách chi trả cao.- **Xây dựng hình ảnh thương hiệu:** Sử dụng lời bảo chứng của khách để nâng cấp vị thế định vị thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('45a845ed-0b32-432d-b869-06ff7bc190cb','7d591057-7425-4a90-888a-8cbb6b2640aa',232,'text','**Nhóm E: Dormant Patient (Bệnh nhân đã lâu không quay lại)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('69b80591-19b1-428e-9f9e-39d3a0b3b4d8','7d591057-7425-4a90-888a-8cbb6b2640aa',233,'text','- **Định nghĩa:** Khách hàng cũ đã quá hạn lịch hẹn tái khám định kỳ từ 9 đến 12 tháng trở lên mà chưa phát sinh thêm bất kỳ tương tác hay lượt khám mới nào tại phòng khám.- **Mục tiêu vận hành:****Kích hoạt lại (Re-activate):** Lọc dữ liệu để chủ động liên hệ lại, tìm hiểu lý do khách chưa quay lại.- **Nhắc kiểm tra sức khỏe:** Cảnh báo các nguy cơ răng miệng nếu bỏ qua chu kỳ cạo vôi, kiểm tra định kỳ.- **Đề xuất ưu đãi cá nhân hóa:** Gửi tặng mã tri ân riêng để thúc đẩy hành vi đặt lịch.- **Tái kết nối:** Đưa khách hàng trở lại đường ống chăm sóc chủ động của Patient OS.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2496d645-b430-4e3c-ad9f-16299d85c215','27-patient-os','f9c5acb4-95dc-49c3-b7e9-dac992d6ddc3',3,'Ma Trận Quản Trị Phân Tầng Bệnh Nhân Trên CRM','ma-tran-quan-tri-phan-tang-benh-nhan-tren-crm',81,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e80b0ce8-da32-4747-8d48-d84ec55c9d4b','2496d645-b430-4e3c-ad9f-16299d85c215',234,'image',NULL,'book/27-patient-os/a05e5061-dc65-4fe5-9a5b-62294f7b0f31-img27.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bed877b9-9e35-4342-bff7-d8c21d33ac4d','2496d645-b430-4e3c-ad9f-16299d85c215',235,'text','**Mantra điều hành phân tầng:***"Hệ thống Patient OS chuẩn xác không cho phép nhân sự đối xử với mọi hồ sơ theo cùng một cách. Hãy nhìn vào trạng thái thực tế của bệnh nhân trên CRM để đưa ra đúng thứ họ cần: Nhóm A cần niềm tin để bắt đầu, Nhóm B cần kỷ luật để đi tiếp, Nhóm C cần sự trân trọng để gắn bó, Nhóm D cần đặc quyền để lan tỏa và Nhóm E cần một lý do tử tế để quay trở lại."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1b91f4fa-8ea4-4de0-88e1-f58766371776','27-patient-os',NULL,2,'27.9 Patient Journey trong Patient OS','279-patient-journey-trong-patient-os',82,'[]');
