INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bbd2769d-65e7-4f34-b08d-78d8e8a76739','0543ff19-6f72-41af-89bb-e7ac77eb6dd4',239,'text','- Các chỉ số từ **1 đến 4** được đối soát theo tần suất **Hằng tuần** để kịp thời tinh chỉnh kịch bản trò chuyện của Lễ tân và Sales Online.- Các chỉ số từ **5 đến 7** được đối soát theo tần suất **Hằng tháng** để đánh giá lại chiến lược giữ chân và chất lượng trải nghiệm tổng thể của phòng khám.',NULL,NULL,NULL,NULL,NULL);
