INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('35037192-6e28-4e26-b83d-f3779f3eba2f','cbe4705d-e87f-405c-b369-f8920f6d5cb6',241,'image',NULL,'book/27-patient-os/838d4c38-983f-463f-882f-b563b34d94ab-img31.png','image.png','image/png','image.png',NULL);
