INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f0f533f5-312b-45c2-a0cd-8c66c4de49a5','cbe4705d-e87f-405c-b369-f8920f6d5cb6',243,'text','**Cơ Chế Thu Thập Và Điều Hành Dựa Trên Dữ Liệu Trải Nghiệm**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8d6be96-fbe9-4ab0-b0fa-d2aabd205b2a','cbe4705d-e87f-405c-b369-f8920f6d5cb6',244,'text','- **Thu thập tự động (Zero-Friction):** Ngay sau khi trạng thái hồ sơ chuyển sang `Checked Out` hoặc hoàn tất một mốc điều trị, hệ thống CRM tự động bắn một form khảo sát ngắn gồm 2 câu hỏi qua Zalo OA của khách. Khách chỉ cần chạm chọn mức sao và viết góp ý (nếu có).- **Kích hoạt cảnh báo đỏ (Red Alert):** Nếu bất kỳ phiếu khảo sát nào có điểm số **\\le 3**** sao**, CRM lập tức đóng gói thành một Ticket sự cố khẩn cấp, đẩy thông báo trực tiếp đến điện thoại của Quản lý phòng khám để kích hoạt quy trình xử lý lỗi ngay trong ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('814db081-fb30-4a71-ac63-8754034c3293','cbe4705d-e87f-405c-b369-f8920f6d5cb6',245,'text','**Mantra điều hành KPI trải nghiệm:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0344ab69-5452-4c03-8349-a988adbcf5a8','cbe4705d-e87f-405c-b369-f8920f6d5cb6',246,'text','*"Con số doanh thu chỉ phản ánh những gì phòng khám đã lấy được từ túi tiền của bệnh nhân trong quá khứ. Chỉ số KPI trải nghiệm mới là thứ dự báo chính xác lượng tiền khách hàng sẽ tiếp tục mang đến cho phòng khám trong tương lai. Hãy kiểm soát chặt chẽ từng điểm chạm để không bao giờ đánh mất lòng tin của người bệnh."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5f5cf7f7-7750-464f-9dde-db59182e7e3f','27-patient-os','9112151e-a24e-4822-b565-163ca9d174d5',3,'KPI tăng trưởng','kpi-tang-truong',87,'[]');
