INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5e27a617-d637-4d29-833a-7c9a241de2df','5f5cf7f7-7750-464f-9dde-db59182e7e3f',248,'image',NULL,'book/27-patient-os/be53cdb8-0348-411f-b2c6-55025fccfc84-img34.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b7f58d63-75ea-4175-b834-7020257326ad','5f5cf7f7-7750-464f-9dde-db59182e7e3f',249,'text','**Mantra điều hành KPI tăng trưởng:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('343bde7e-5fb3-4f5f-bb82-f66b3a338d04','5f5cf7f7-7750-464f-9dde-db59182e7e3f',250,'text','*"Một hệ thống Patient OS vận hành xuất sắc là khi các chỉ số tăng trưởng hữu cơ này tăng trưởng đều qua từng tháng, giúp giảm tải áp lực tài chính cho bộ máy quảng cáo. Lòng tin của bệnh nhân chính là nguồn vốn tự có lớn nhất của phòng khám."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('40240d4a-65cb-4bf0-84bc-aa02122d340d','27-patient-os',NULL,2,'27.12. Service Recovery OS - Quy Trình Xử Lý Phản Hồi Tiêu Cực Và Giải Tỏa Khiếu Nại','2712-service-recovery-os-quy-trinh-xu-ly-phan-hoi-tieu-cuc-va-giai-toa-khieu-nai',88,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1771cfbc-0cf9-4e55-b789-31960e0738a5','40240d4a-65cb-4bf0-84bc-aa02122d340d',251,'text','Hệ điều hành Patient OS không chỉ vận hành trong điều kiện lý tưởng khi bệnh nhân hài lòng, mà quan trọng hơn, nó phải là tấm lá chắn xử lý khủng hoảng khi xảy ra sự cố. Một phản hồi tiêu cực (khiếu nại, bức xúc) nếu được xử lý chuyên nghiệp và kịp thời sẽ là cơ hội lớn để cứu vãn lòng tin, biến một khách hàng đang giận dữ thành một người bảo vệ trung thành cho nha khoa  Ngược lại, sự chậm trễ hoặc đối thoại cảm tính sẽ phá hủy uy tín của phòng khám ngay lập tức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f19e2a1c-0d99-4c41-b3c1-e41616ba1aeb','40240d4a-65cb-4bf0-84bc-aa02122d340d',252,'image',NULL,'book/27-patient-os/69d1df1b-e0e4-4275-b999-a72bf2d6f3fb-img35.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('41f02c99-6a0d-4ef8-876a-ea013efb71ea','27-patient-os','40240d4a-65cb-4bf0-84bc-aa02122d340d',3,'Bảy Nguyên Tắc Vàng Khi Tiếp Cận Bệnh Nhân Sự Cố','bay-nguyen-tac-vang-khi-tiep-can-benh-nhan-su-co',89,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('414e1dd4-3155-46f0-8f4d-43dec161270b','41f02c99-6a0d-4ef8-876a-ea013efb71ea',253,'image',NULL,'book/27-patient-os/d3bf09dd-7b41-4110-bcd3-f621ad46c90f-img36.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9da568f-b150-45e0-a21c-73954bd55ff6','41f02c99-6a0d-4ef8-876a-ea013efb71ea',254,'text','Trước khi thực hiện liên hệ với bệnh nhân, toàn bộ nhân sự phụ trách tại cơ sở Hà Nội bắt buộc phải tuân thủ tuyệt đối 7 nguyên tắc cốt lõi dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('241b680b-f7c5-42ea-8bd9-871c47273bdb','41f02c99-6a0d-4ef8-876a-ea013efb71ea',255,'text','- **Không tranh cãi với bệnh nhân:** Tuyệt đối không phân bua đúng sai hay phản kháng lại sự nóng giận của khách.- **Không đổ lỗi cho bệnh nhân:** Không dùng các lý do cá nhân (ví dụ: *"do anh/chị không vệ sinh kỹ tại nhà"*) để né tránh trách nhiệm ban đầu của phòng khám.- **Không phản hồi cảm tính:** Không dùng ngôn từ mang tính cá nhân, luôn giữ thái độ lịch sự, chừng mực và sử dụng ngôn ngữ dịch vụ chuẩn mực.- **Lắng nghe trước khi giải thích:** Hãy để khách hàng xả hết bức xúc, ghi nhận đầy đủ chi tiết trước khi đưa ra lý do lâm sàng hay vận hành.- **Có người phụ trách rõ ràng:** Mỗi ca sự cố phải được phân quyền cụ thể cho một nhân sự làm đầu mối xử lý dứt điểm từ đầu đến cuối, tránh việc đùn đẩy trách nhiệm.- **Có thời hạn xử lý cứng (SLA):** Đảm bảo thời gian giải quyết sự cố phải nằm trong khung giờ quy định để đánh chặn rủi ro khủng hoảng lan rộng trên internet.- **Ghi nhận để cải thiện hệ thống:** Xem mỗi lỗi sai là một dữ liệu thực tế để tìm ra lỗ hổng vận hành và vá lại quy trình tổng.',NULL,NULL,NULL,NULL,NULL);
