INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0752a425-5b07-4130-89b7-ffb1a18bbea4','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',268,'text','Áp dụng ma trận phân loại (Mức 1, 2, 3) để chuyển giao quyền xử lý và Payload thông tin cho đúng bộ phận chuyên trách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fee3a135-3bcb-4ba5-8983-cd38e76c6b9b','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',269,'text','**3.4. Liên hệ trực tiếp với bệnh nhân:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf00f806-93cb-440c-9d99-4f2a8b01d5f3','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',270,'text','*Chặng 4: Tiếp cận.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ddf3f673-0d04-4683-858e-50bec8e0364d','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',271,'text','Nhân sự được phân quyền chủ động gọi điện thoại hoặc mời khách vào phòng VIP riêng tư tại cơ sở Hà Nội để trao đổi, tuyệt đối không đôi co bằng văn bản trên bình luận công khai.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb9d8b0f-c291-4ea7-b427-32800c62ce79','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',272,'text','**3.5. Lắng nghe và Xác nhận vấn đề:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2673cc7f-1cc5-46c8-afd9-198807829829','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',273,'text','*Chặng 5: Thấu cảm.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b3e808ed-f61b-4f18-b925-b2328272d61a','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',274,'text','Để bệnh nhân nói rõ toàn bộ sự việc mà không ngắt lời. Sử dụng ngôn từ ghi nhận: *"Em đã nắm được tình trạng của mình và rất tiếc vì anh/chị đã có trải nghiệm không thoải mái này tại phòng khám"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c43d7989-41a5-4569-8149-b9eaeec01954','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',275,'text','**3.6. Đưa phương án xử lý trực diện:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4997692-1987-4e9d-9219-2e91d7d66925','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',276,'text','*Chặng 6: Khắc phục.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0000a2e9-c457-45b0-82d4-825d5a4e3643','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',277,'text','Đề xuất giải pháp khắc phục cụ thể và thực tế (Mời qua phòng khám kiểm tra miễn phí ngay, điều chỉnh lịch hẹn ưu tiên, hoặc xử lý bảo hành kỹ thuật cao).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a9946425-ed51-4d9a-9497-3162e18188de','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',278,'text','**3.7. Theo dõi sát sau xử lý:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0ba7fba-46b1-40c5-b257-3555169f5994','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',279,'text','*Chặng 7: Giám sát.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fc42732a-3b05-4ab3-b168-8dc816fd472a','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',280,'text','Sau khi giải quyết xong xuôi tại sàn, bộ phận CSKH liên hệ lại sau 24h - 48h để kiểm tra xem tình trạng răng miệng đã thực sự ổn định chưa và đo lường lại mức độ đón nhận của khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a0c33ab-5111-4c48-9e30-acd0eddade0f','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',281,'text','**3.8. Đóng Ticket và Đúc rút bài học vào hệ thống:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('536fba19-a37b-4743-b31c-d142c7651bc9','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',282,'text','*Chặng 8: Đóng ca.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('17604969-3739-403a-b74d-2938e0bc8d88','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',283,'text','Đóng hồ sơ sự cố trên CRM khi khách hàng xác nhận đồng ý. Quản lý đưa trường hợp này vào buổi họp giao ban tuần để phân tích nguyên nhân gốc rễ và cập nhật văn bản sửa đổi quy trình vận hành chung của bộ máy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96bfd885-49ee-4a8b-bc7d-aaee851152bc','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',284,'text','**Mantra điều hành xử lý phản hồi:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15c92da7-20dc-4567-912c-cb4e64bd30fb','ccd9816b-8c68-4b1f-985a-beaa0e64ecc9',285,'text','*"Khi bệnh nhân phàn nàn, họ đang trao cho phòng khám cơ hội cuối cùng để sửa sai. Hãy đón nhận sự giận dữ của họ bằng cái đầu lạnh của quy trình và trái tim ấm của sự thấu cảm. Cách chúng ta ứng xử lúc xảy ra sự cố chính là bộ lọc chính xác nhất bản chất dịch vụ tử tế của nha khoa Thích Làm Răng."*',NULL,NULL,NULL,NULL,NULL);
